        }

        private static void EnsureArrowObjectId(ArrowObject arrowObject)
        {
            if (arrowObject == null)
            {
                return;
            }

            if (string.IsNullOrWhiteSpace(arrowObject.Id))
            {
                arrowObject.Id = Guid.NewGuid().ToString("N");
