        }

        private static void EnsureVectorShapeId(VectorShapeObject vectorShape)
        {
            if (vectorShape == null)
            {
                return;
            }

            if (string.IsNullOrWhiteSpace(vectorShape.Id))
            {
                vectorShape.Id = Guid.NewGuid().ToString("N");
