        private void ButtonRedactText_Click(object sender, EventArgs e)
        {

            if (pagesToRemove.Count == numPages)
            {
                MessageBox.Show(this, Resources.Err_AllPagesMarked, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            if (!EnsureInterestSubjectForRequiredBases())
            {
                return;
            }

            using (SaveFileDialog saveFileDialog = new SaveFileDialog())
            {
                saveFileDialog.Filter = Resources.Dialog_Filter_PDF;
                saveFileDialog.Title = Resources.Dialog_Title_SavePdfAs;
                saveFileDialog.FileName = $"{System.IO.Path.GetFileNameWithoutExtension(inputPdfPath)}_anon.pdf";

                if (saveFileDialog.ShowDialog(this) == DialogResult.OK)
                {
                    try
                    {
                        this.Cursor = Cursors.WaitCursor;

                        string tempFile = Path.Combine(Path.GetTempPath(), $"pdfreencoded_{DateTime.Now.Ticks}.pdf");
                        bool retReencoding = ReencodePdfKeepOriginalCompression(inputPdfPath, tempFile);

                        if (retReencoding)
                        {
                            RedactText(tempFile, saveFileDialog.FileName, reencodedPages);
                        }
                        else
                        {
                            RedactText(inputPdfPath, saveFileDialog.FileName);
                        }


                        // Delete existing file if it exists
                        if (File.Exists(tempFile))
                        {
                            File.Delete(tempFile);
                        }
                        this.Cursor = Cursors.Default;
                        if (openSavedPDFCheckBox.Checked)
                        {
                            try
                            {
                                // Temporarily exit fullscreen to allow external viewer to show
                                ExitFullScreenIfNeeded();

                                var psi = new ProcessStartInfo
                                {
                                    FileName = saveFileDialog.FileName,
                                    UseShellExecute = true
                                };
                                Process.Start(psi);
                            }
                            catch (System.ComponentModel.Win32Exception wex)
                            {
                                MessageBox.Show(this, string.Format(Resources.Err_NoAssociatedPdfApp, wex.Message), Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                            }
                        }
                        OpenDiagnosticLogIfEnabled();
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show(this, string.Format(Resources.Err_Save, ex.Message), Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
                        this.Cursor = Cursors.Default;
                    }
                }
            }
        }

        private ZoomPanel GetZoomPanel()
        {
            if (mainAppSplitContainer.Panel2.Controls.Count == 0)
            {
                return null;
            }

            return mainAppSplitContainer.Panel2.Controls[0] as ZoomPanel;
        }

        private static int GetScrollMaximum(ScrollProperties scroll)
        {
            int max = scroll.Maximum - scroll.LargeChange + 1;
            return max < scroll.Minimum ? scroll.Minimum : max;
        }

        private static int ClampScrollValue(int value, int min, int max)
        {
            if (value < min)
            {
                return min;
            }

            if (value > max)
            {
                return max;
            }

            return value;
        }

        private static bool ArePathsEqual(string left, string right)
        {
            if (string.IsNullOrWhiteSpace(left) || string.IsNullOrWhiteSpace(right))
            {
                return false;
            }

            try
            {
                string normalizedLeft = Path.GetFullPath(left.Trim());
                string normalizedRight = Path.GetFullPath(right.Trim());
                return string.Equals(normalizedLeft, normalizedRight, StringComparison.OrdinalIgnoreCase);
            }
            catch
            {
                return string.Equals(left.Trim(), right.Trim(), StringComparison.OrdinalIgnoreCase);
            }
        }

        private static string GetUserDataDirectory()
        {
            string userDir = LicenseManager.UserLicenseDirectory;
            if (!string.IsNullOrWhiteSpace(userDir))
            {
                return userDir;
            }

            return Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                "MISART",
                "AnonPDFPro");
        }

        private static string GetResumeStateFilePath()
        {
            return Path.Combine(GetUserDataDirectory(), "resume-state.json");
        }

        private static string GetAutoResumeProjectFilePath()
        {
            return Path.Combine(GetUserDataDirectory(), "resume-project.app");
        }

        private static string GetGlobalExclusionScopesFilePath()
        {
            return Path.Combine(Application.StartupPath, "exclusion_scopes.json");
        }

        private static string GetLocalExclusionScopesFilePath()
        {
            return Path.Combine(GetUserDataDirectory(), "user_exclusion_scopes.json");
        }

        private static string GetGlobalLegalBasesFilePath()
        {
            return Path.Combine(Application.StartupPath, "legal_bases.json");
        }

        private static string GetLocalLegalBasesFilePath()
        {
            return Path.Combine(GetUserDataDirectory(), "user_legal_bases.json");
        }

        private void LoadFootnotesCatalog()
        {
            exclusionScopesCatalog.Clear();
            exclusionScopesById.Clear();
            legalBasesCatalog.Clear();
            legalBasesById.Clear();
            footnotesCatalogLoadWarnings.Clear();

            globalExclusionScopesPath = GetGlobalExclusionScopesFilePath();
            localExclusionScopesPath = GetLocalExclusionScopesFilePath();
            globalLegalBasesPath = GetGlobalLegalBasesFilePath();
            localLegalBasesPath = GetLocalLegalBasesFilePath();

            canWriteGlobalExclusionScopes = HasWriteAccessToTarget(globalExclusionScopesPath);
            canWriteGlobalLegalBases = HasWriteAccessToTarget(globalLegalBasesPath);

            LoadMergedExclusionScopesCatalog();
            LoadMergedLegalBasesCatalog();

            if (footnotesCatalogLoadWarnings.Count > 0)
            {
                LogDebug("Footnotes catalog warnings: " + string.Join(" | ", footnotesCatalogLoadWarnings));
            }

            LogDebug(
                $"Footnotes catalog loaded scopes={exclusionScopesCatalog.Count} legalBases={legalBasesCatalog.Count} " +
                $"globalScopesWritable={canWriteGlobalExclusionScopes} globalLegalWritable={canWriteGlobalLegalBases}");
        }

        private void LoadMergedExclusionScopesCatalog()
        {
            if (TryLoadCatalogFile(globalExclusionScopesPath, out ExclusionScopesCatalogFile globalFile, out string globalError))
            {
                AddExclusionScopesToCatalog(globalFile.ExclusionScopes, ExclusionScopeSource.Global, globalExclusionScopesPath);
            }
            else if (!string.IsNullOrWhiteSpace(globalError))
            {
                footnotesCatalogLoadWarnings.Add(globalError);
            }

            if (TryLoadCatalogFile(localExclusionScopesPath, out ExclusionScopesCatalogFile localFile, out string localError))
            {
                AddExclusionScopesToCatalog(localFile.ExclusionScopes, ExclusionScopeSource.Local, localExclusionScopesPath);
            }
            else if (!string.IsNullOrWhiteSpace(localError))
            {
                footnotesCatalogLoadWarnings.Add(localError);
            }
        }

        private void AddExclusionScopesToCatalog(IEnumerable<ExclusionScopeDefinition> scopes, ExclusionScopeSource source, string sourcePath)
        {
            if (scopes == null)
            {
                return;
            }

            foreach (var scope in scopes)
            {
                if (!NormalizeScopeDefinition(scope, source))
                {
                    continue;
                }

                if (exclusionScopesById.ContainsKey(scope.ScopeId))
                {
                    footnotesCatalogLoadWarnings.Add($"Duplicate scope_id '{scope.ScopeId}' in {sourcePath}. Entry skipped.");
                    continue;
                }

                exclusionScopesCatalog.Add(scope);
                exclusionScopesById[scope.ScopeId] = scope;
            }
        }

        private void LoadMergedLegalBasesCatalog()
        {
            if (TryLoadCatalogFile(globalLegalBasesPath, out LegalBasesCatalogFile globalFile, out string globalError))
            {
                AddLegalBasesToCatalog(globalFile.LegalBases, LegalBasisSource.Global, globalLegalBasesPath);
            }
            else if (!string.IsNullOrWhiteSpace(globalError))
            {
                footnotesCatalogLoadWarnings.Add(globalError);
            }

            if (TryLoadCatalogFile(localLegalBasesPath, out LegalBasesCatalogFile localFile, out string localError))
            {
                AddLegalBasesToCatalog(localFile.LegalBases, LegalBasisSource.Local, localLegalBasesPath);
            }
            else if (!string.IsNullOrWhiteSpace(localError))
            {
                footnotesCatalogLoadWarnings.Add(localError);
            }
        }

        private bool TryLoadLegalBasesForEditor(
            string path,
            LegalBasisSource source,
            out List<LegalBasisDefinition> legalBases,
            out string errorMessage)
        {
            legalBases = new List<LegalBasisDefinition>();
            errorMessage = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return true;
            }

            if (!TryLoadCatalogFile(path, out LegalBasesCatalogFile catalogFile, out string loadError))
            {
                string prefix = source == LegalBasisSource.Global
                    ? GetLegalBasesLoadGlobalErrorPrefix()
                    : GetLegalBasesLoadLocalErrorPrefix();
                errorMessage = $"{prefix}\n{loadError}";
                return false;
            }

            foreach (var entry in catalogFile.LegalBases ?? new List<LegalBasisDefinition>())
            {
                var clonedEntry = CloneLegalBasisDefinition(entry);
                if (NormalizeLegalBasisDefinition(clonedEntry, source))
                {
                    legalBases.Add(clonedEntry);
                }
            }

            return true;
        }

        private bool TrySaveLegalBasesForEditor(
            string path,
            string sourceName,
            LegalBasisSource sourceKind,
            IEnumerable<LegalBasisDefinition> legalBases,
            out string errorMessage)
        {
            errorMessage = string.Empty;
            var normalizedEntries = new List<LegalBasisDefinition>();
            var usedIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var entry in legalBases ?? Enumerable.Empty<LegalBasisDefinition>())
            {
                var clonedEntry = CloneLegalBasisDefinition(entry);
                if (!NormalizeLegalBasisDefinition(clonedEntry, sourceKind))
                {
                    errorMessage = GetLegalBasesSaveInvalidEntryMessage();
                    return false;
                }

                if (!usedIds.Add(clonedEntry.Id))
                {
                    errorMessage = string.Format(GetLegalBasesSaveDuplicateIdMessage(), clonedEntry.Id);
                    return false;
                }

                normalizedEntries.Add(clonedEntry);
            }

            try
            {
                string directoryPath = Path.GetDirectoryName(path);
                if (!string.IsNullOrWhiteSpace(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                var catalogFile = new LegalBasesCatalogFile
                {
                    Source = sourceName,
                    LegalBases = normalizedEntries
                };

                string json = JsonConvert.SerializeObject(catalogFile, Formatting.Indented);
                File.WriteAllText(path, json);
                return true;
            }
            catch (Exception ex)
            {
                string prefix = sourceKind == LegalBasisSource.Global
                    ? GetLegalBasesSaveGlobalErrorPrefix()
                    : GetLegalBasesSaveLocalErrorPrefix();
                errorMessage = $"{prefix}\n{ex.Message}";
                return false;
            }
        }

        private bool TryLoadExclusionScopesForEditor(
            string path,
            ExclusionScopeSource source,
            out List<ExclusionScopeDefinition> scopes,
            out string version,
            out string errorMessage)
        {
            scopes = new List<ExclusionScopeDefinition>();
            version = "1.0";
            errorMessage = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return true;
            }

            if (!TryLoadCatalogFile(path, out ExclusionScopesCatalogFile catalogFile, out string loadError))
            {
                string prefix = source == ExclusionScopeSource.Global
                    ? GetExclusionScopesLoadGlobalErrorPrefix()
                    : GetExclusionScopesLoadLocalErrorPrefix();
                errorMessage = $"{prefix}\n{loadError}";
                return false;
            }

            if (!string.IsNullOrWhiteSpace(catalogFile.Version))
            {
                version = catalogFile.Version.Trim();
            }

            foreach (var entry in catalogFile.ExclusionScopes ?? new List<ExclusionScopeDefinition>())
            {
                var clonedEntry = CloneExclusionScopeDefinition(entry);
                if (NormalizeScopeDefinition(clonedEntry, source))
                {
                    scopes.Add(clonedEntry);
                }
            }

            return true;
        }

        private bool TrySaveExclusionScopesForEditor(
            string path,
            string version,
            ExclusionScopeSource source,
            IEnumerable<ExclusionScopeDefinition> scopes,
            out string errorMessage)
        {
            errorMessage = string.Empty;
            var normalizedScopes = new List<ExclusionScopeDefinition>();
            var usedScopeIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var entry in scopes ?? Enumerable.Empty<ExclusionScopeDefinition>())
            {
                var clonedEntry = CloneExclusionScopeDefinition(entry);
                if (!NormalizeScopeDefinition(clonedEntry, source))
                {
                    errorMessage = GetExclusionScopesSaveInvalidEntryMessage();
                    return false;
                }

                if (!usedScopeIds.Add(clonedEntry.ScopeId))
                {
                    errorMessage = string.Format(GetExclusionScopesSaveDuplicateIdMessage(), clonedEntry.ScopeId);
                    return false;
                }

                normalizedScopes.Add(clonedEntry);
            }

            try
            {
                string directoryPath = Path.GetDirectoryName(path);
                if (!string.IsNullOrWhiteSpace(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                var catalogFile = new ExclusionScopesCatalogFile
                {
                    Version = string.IsNullOrWhiteSpace(version) ? "1.0" : version.Trim(),
                    ExclusionScopes = normalizedScopes
                };

                string json = JsonConvert.SerializeObject(catalogFile, Formatting.Indented);
                File.WriteAllText(path, json);
                return true;
            }
            catch (Exception ex)
            {
                string prefix = source == ExclusionScopeSource.Global
                    ? GetExclusionScopesSaveGlobalErrorPrefix()
                    : GetExclusionScopesSaveLocalErrorPrefix();
                errorMessage = $"{prefix}\n{ex.Message}";
                return false;
            }
        }

        private static LegalBasisDefinition CloneLegalBasisDefinition(LegalBasisDefinition source)
        {
            if (source == null)
            {
                return new LegalBasisDefinition();
            }

            return new LegalBasisDefinition
            {
                Id = source.Id,
                Title = source.Title,
                FullCitation = source.FullCitation,
                RequiresInterestSubject = source.RequiresInterestSubject,
                DescriptionHint = source.DescriptionHint,
                SourceKind = source.SourceKind
            };
        }

        private static ExclusionScopeDefinition CloneExclusionScopeDefinition(ExclusionScopeDefinition source)
        {
            if (source == null)
            {
                return new ExclusionScopeDefinition();
            }

            return new ExclusionScopeDefinition
            {
                ScopeId = source.ScopeId,
                FriendlyName = source.FriendlyName,
                Category = source.Category,
                Description = source.Description,
                AutoDetectTags = new List<string>(source.AutoDetectTags ?? new List<string>()),
                DefaultBasisIds = new List<string>(source.DefaultBasisIds ?? new List<string>()),
                UiColor = source.UiColor,
                SourceKind = source.SourceKind
            };
        }

        private void AddLegalBasesToCatalog(IEnumerable<LegalBasisDefinition> legalBases, LegalBasisSource source, string sourcePath)
        {
            if (legalBases == null)
            {
                return;
            }

            foreach (var legalBasis in legalBases)
            {
                if (!NormalizeLegalBasisDefinition(legalBasis, source))
                {
                    continue;
                }

                if (legalBasesById.ContainsKey(legalBasis.Id))
                {
                    footnotesCatalogLoadWarnings.Add($"Duplicate legal base id '{legalBasis.Id}' in {sourcePath}. Entry skipped.");
                    continue;
                }

                legalBasesCatalog.Add(legalBasis);
                legalBasesById[legalBasis.Id] = legalBasis;
            }
        }

        private static bool NormalizeScopeDefinition(ExclusionScopeDefinition scope, ExclusionScopeSource source)
        {
            if (scope == null)
            {
                return false;
            }

            scope.ScopeId = string.IsNullOrWhiteSpace(scope.ScopeId) ? null : scope.ScopeId.Trim();
            if (string.IsNullOrWhiteSpace(scope.ScopeId))
            {
                return false;
            }

            scope.FriendlyName = string.IsNullOrWhiteSpace(scope.FriendlyName) ? scope.ScopeId : scope.FriendlyName.Trim();
            scope.Category = string.IsNullOrWhiteSpace(scope.Category) ? string.Empty : scope.Category.Trim();
            scope.Description = string.IsNullOrWhiteSpace(scope.Description) ? string.Empty : scope.Description.Trim();
            scope.UiColor = string.IsNullOrWhiteSpace(scope.UiColor) ? string.Empty : scope.UiColor.Trim();

            scope.AutoDetectTags = (scope.AutoDetectTags ?? new List<string>())
                .Where(tag => !string.IsNullOrWhiteSpace(tag))
                .Select(tag => tag.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            scope.DefaultBasisIds = (scope.DefaultBasisIds ?? new List<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            scope.SourceKind = source;

            return true;
        }

        private static bool NormalizeLegalBasisDefinition(LegalBasisDefinition legalBasis, LegalBasisSource source)
        {
            if (legalBasis == null)
            {
                return false;
            }

            legalBasis.Id = string.IsNullOrWhiteSpace(legalBasis.Id) ? null : legalBasis.Id.Trim();
            if (string.IsNullOrWhiteSpace(legalBasis.Id))
            {
                return false;
            }

            legalBasis.Title = string.IsNullOrWhiteSpace(legalBasis.Title) ? legalBasis.Id : legalBasis.Title.Trim();
            legalBasis.FullCitation = string.IsNullOrWhiteSpace(legalBasis.FullCitation) ? string.Empty : legalBasis.FullCitation.Trim();
            legalBasis.DescriptionHint = string.IsNullOrWhiteSpace(legalBasis.DescriptionHint) ? string.Empty : legalBasis.DescriptionHint.Trim();
            legalBasis.SourceKind = source;
            return true;
        }

        private static bool TryLoadCatalogFile<T>(string path, out T data, out string error)
            where T : class
        {
            data = null;
            error = string.Empty;

            if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
            {
                return false;
            }

            try
            {
                string json = File.ReadAllText(path);
                data = JsonConvert.DeserializeObject<T>(json);
                if (data == null)
                {
                    error = $"File '{path}' contains empty or invalid JSON object.";
                    return false;
                }

                return true;
            }
            catch (Exception ex)
            {
                error = $"Cannot load '{path}': {ex.Message}";
                return false;
            }
        }

        private static bool HasWriteAccessToTarget(string targetPath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(targetPath))
                {
                    return false;
                }

                if (File.Exists(targetPath))
                {
                    using (FileStream fs = File.Open(targetPath, FileMode.Open, FileAccess.Write, FileShare.ReadWrite))
                    {
                    }
                    return true;
                }

                string directoryPath = Path.GetDirectoryName(targetPath);
                if (string.IsNullOrWhiteSpace(directoryPath))
                {
                    return false;
                }

                if (!Directory.Exists(directoryPath))
                {
                    Directory.CreateDirectory(directoryPath);
                }

                string probeFilePath = Path.Combine(directoryPath, $".write_probe_{Guid.NewGuid():N}.tmp");
                File.WriteAllText(probeFilePath, "probe");
                File.Delete(probeFilePath);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private bool IsAutoResumeProjectPath(string path)
        {
            return ArePathsEqual(path, GetAutoResumeProjectFilePath());
        }

        private string GetCurrentProjectPath()
        {
            if (!string.IsNullOrWhiteSpace(lastSavedProjectName))
            {
                return lastSavedProjectName;
            }

            return inputProjectPath;
        }

        private bool HasAnyProjectContent()
        {
            return redactionBlocks.Count > 0
                || textAnnotations.Count > 0
                || rasterObjects.Count > 0
                || arrowObjects.Count > 0
                || vectorShapes.Count > 0
                || pagesToRemove.Count > 0
                || pageRotationOffsets.Count > 0
                || hasCustomSignatureSelection;
        }

        private ProjectData BuildCurrentProjectDataSnapshot(bool includeViewState)
        {
            float? zoomFactor = null;
            int? scrollX = null;
            int? scrollY = null;

            if (includeViewState)
            {
                CaptureCurrentViewState(out float zf, out int sx, out int sy);
                zoomFactor = zf > 0 ? zf : (float?)null;
                scrollX = sx;
                scrollY = sy;
            }

            return new ProjectData
            {
                RedactionBlocks = redactionBlocks ?? new List<RedactionBlock>(),
                PagesToRemove = pagesToRemove ?? new HashSet<int>(),
                TextAnnotations = textAnnotations ?? new List<TextAnnotation>(),
                RasterObjects = rasterObjects ?? new List<RasterObject>(),
                ArrowObjects = arrowObjects ?? new List<ArrowObject>(),
                VectorShapes = vectorShapes ?? new List<VectorShapeObject>(),
                ObjectLayers = BuildProjectObjectLayersSnapshot(),
                PageRotationOffsets = pageRotationOffsets == null
                    ? new Dictionary<int, int>()
                    : new Dictionary<int, int>(pageRotationOffsets),
                FilePath = inputPdfPath,
                CurrentPage = Math.Max(1, Math.Min(currentPage, Math.Max(1, numPages))),
                ZoomFactor = zoomFactor,
                ScrollX = scrollX,
                ScrollY = scrollY,
                SignaturesMode = GetSignatureModeForProject(),
                SignaturesToRemove = hasCustomSignatureSelection ? new List<string>(signaturesToRemove) : null,
                AutoFootnotesEnabled = autoFootnotesEnabled,
                ExclusionAuthority = exclusionAuthorityName
            };
        }

        private bool TrySaveAutoResumeProjectSnapshot(out string savedPath)
        {
            savedPath = string.Empty;
            if (pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return false;
            }

            if (!string.IsNullOrWhiteSpace(lastSavedProjectName) || !string.IsNullOrWhiteSpace(inputProjectPath))
            {
                return false;
            }

            if (!HasAnyProjectContent())
            {
                return false;
            }

            try
            {
                string autoPath = GetAutoResumeProjectFilePath();
                string dir = Path.GetDirectoryName(autoPath);
                if (!string.IsNullOrWhiteSpace(dir))
                {
                    Directory.CreateDirectory(dir);
                }

                var projectData = BuildCurrentProjectDataSnapshot(includeViewState: true);
                string json = JsonConvert.SerializeObject(projectData, Formatting.Indented);
                File.WriteAllText(autoPath, json);
                savedPath = autoPath;
                return true;
            }
            catch (Exception ex)
            {
                LogDebug("Auto resume project save failed: " + ex.Message);
                return false;
            }
        }

        private void CaptureCurrentViewState(out float zoomFactor, out int scrollX, out int scrollY)
        {
            zoomFactor = scaleFactor;
            scrollX = 0;
            scrollY = 0;

            ZoomPanel panel = GetZoomPanel();
            if (panel is ZoomPanel)
            {
                scrollX = panel.HorizontalScroll.Value;
                scrollY = panel.VerticalScroll.Value;
            }
        }

        private void QueuePendingViewScrollRestore(int scrollX, int scrollY)
        {
            pendingViewScrollX = Math.Max(0, scrollX);
            pendingViewScrollY = Math.Max(0, scrollY);
        }

        private void ApplyPendingViewScrollRestore()
        {
            if (!pendingViewScrollX.HasValue && !pendingViewScrollY.HasValue)
            {
                return;
            }

            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                pendingViewScrollX = null;
                pendingViewScrollY = null;
                return;
            }

            int targetX = pendingViewScrollX ?? panel.HorizontalScroll.Minimum;
            int targetY = pendingViewScrollY ?? panel.VerticalScroll.Minimum;

            targetX = ClampScrollValue(targetX, panel.HorizontalScroll.Minimum, GetScrollMaximum(panel.HorizontalScroll));
            targetY = ClampScrollValue(targetY, panel.VerticalScroll.Minimum, GetScrollMaximum(panel.VerticalScroll));

            panel.AutoScrollPosition = new Point(targetX, targetY);
            pendingViewScrollX = null;
            pendingViewScrollY = null;
        }

        private void PersistResumeState()
        {
            if (pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return;
            }

            try
            {
                CaptureCurrentViewState(out float zoomFactor, out int scrollX, out int scrollY);
                var state = new ResumeState
                {
                    PdfPath = inputPdfPath,
                    ProjectPath = GetCurrentProjectPath(),
                    CurrentPage = Math.Max(1, Math.Min(currentPage, numPages)),
                    ZoomFactor = zoomFactor > 0 ? zoomFactor : (float?)null,
                    ScrollX = scrollX,
                    ScrollY = scrollY
                };

                string stateFilePath = GetResumeStateFilePath();
                string stateDirectory = Path.GetDirectoryName(stateFilePath);
                if (!string.IsNullOrWhiteSpace(stateDirectory))
                {
                    Directory.CreateDirectory(stateDirectory);
                }

                string json = JsonConvert.SerializeObject(state, Formatting.Indented);
                File.WriteAllText(stateFilePath, json);
                LogDebug($"Resume state saved pdf={state.PdfPath} project={state.ProjectPath} page={state.CurrentPage} zoom={(state.ZoomFactor.HasValue ? state.ZoomFactor.Value.ToString(CultureInfo.InvariantCulture) : "-")} scroll={state.ScrollX},{state.ScrollY}");
            }
            catch
            {
                // Keep close flow even if resume-state update fails.
            }
        }

        private static ResumeState LoadResumeState()
        {
            try
            {
                string stateFilePath = GetResumeStateFilePath();
                if (!File.Exists(stateFilePath))
                {
                    return null;
                }

                string json = File.ReadAllText(stateFilePath);
                return JsonConvert.DeserializeObject<ResumeState>(json);
            }
            catch
            {
                return null;
            }
        }

        private void SelectPageInListView(int pageNumber)
        {
            if (pageNumber < 1 || pageNumber > numPages)
            {
                return;
            }

            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                if (pageNumber - 1 < pagesListView.Items.Count)
                {
                    pagesListView.Items[pageNumber - 1].Selected = true;
                    pagesListView.Items[pageNumber - 1].EnsureVisible();
                }
            }
            else
            {
                ListViewItem currentItem = FindListViewItemByPageNumber(pageNumber);
                if (currentItem != null)
                {
                    currentItem.Selected = true;
                    currentItem.EnsureVisible();
                }
            }
        }

        private void RestoreViewFromResumeStateIfMatches(ResumeState state)
        {
            if (state == null || pdf == null || numPages <= 0 || string.IsNullOrWhiteSpace(inputPdfPath))
            {
                return;
            }

            string currentProjectPath = GetCurrentProjectPath();
            bool projectMatch = !string.IsNullOrWhiteSpace(currentProjectPath) && ArePathsEqual(state.ProjectPath, currentProjectPath);
            bool pdfMatch = ArePathsEqual(state.PdfPath, inputPdfPath);
            if (!projectMatch && !pdfMatch)
            {
                LogDebug($"Resume state skipped (path mismatch) statePdf={state.PdfPath} stateProject={state.ProjectPath} currentPdf={inputPdfPath} currentProject={currentProjectPath}");
                return;
            }

            if (state.CurrentPage > 0)
            {
                currentPage = Math.Max(1, Math.Min(state.CurrentPage, numPages));
            }

            if (state.ZoomFactor.HasValue && state.ZoomFactor.Value > 0)
            {
                scaleFactor = state.ZoomFactor.Value;
                pendingScaleFactor = scaleFactor;
                minScaleButton = false;
                maxScaleButton = false;
            }

            QueuePendingViewScrollRestore(state.ScrollX, state.ScrollY);
            SelectPageInListView(currentPage);
            ReloadRefreshCurrentPage();
            UpdateNavigationButtons(currentPage);
            LogDebug($"Resume state applied page={currentPage} zoom={scaleFactor.ToString(CultureInfo.InvariantCulture)} scroll={state.ScrollX},{state.ScrollY}");
        }

        private bool TryBeginMiddleMousePan()
        {
            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                return false;
            }

            bool canPanX = panel.HorizontalScroll.Visible && GetScrollMaximum(panel.HorizontalScroll) > panel.HorizontalScroll.Minimum;
            bool canPanY = panel.VerticalScroll.Visible && GetScrollMaximum(panel.VerticalScroll) > panel.VerticalScroll.Minimum;
            if (!canPanX && !canPanY)
            {
                return false;
            }

            isMiddleMousePanning = true;
            middlePanStartCursorScreen = Cursor.Position;
            middlePanStartScrollX = panel.HorizontalScroll.Value;
            middlePanStartScrollY = panel.VerticalScroll.Value;
            middlePanPreviousCursor = this.Cursor;
            this.Cursor = Cursors.SizeAll;
            pdfViewer.Capture = true;
            return true;
        }

        private void UpdateMiddleMousePan()
        {
            if (!isMiddleMousePanning)
            {
                return;
            }

            if ((Control.MouseButtons & MouseButtons.Middle) == 0)
            {
                EndMiddleMousePan();
                return;
            }

            ZoomPanel panel = GetZoomPanel();
            if (!(panel is ZoomPanel))
            {
                EndMiddleMousePan();
                return;
            }

            Point cursorScreen = Cursor.Position;
            int deltaX = cursorScreen.X - middlePanStartCursorScreen.X;
            int deltaY = cursorScreen.Y - middlePanStartCursorScreen.Y;

            int targetX = ClampScrollValue(
                middlePanStartScrollX - deltaX,
                panel.HorizontalScroll.Minimum,
                GetScrollMaximum(panel.HorizontalScroll));
            int targetY = ClampScrollValue(
                middlePanStartScrollY - deltaY,
                panel.VerticalScroll.Minimum,
                GetScrollMaximum(panel.VerticalScroll));

            bool horizontalChanged = panel.HorizontalScroll.Visible && panel.HorizontalScroll.Value != targetX;
            bool verticalChanged = panel.VerticalScroll.Visible && panel.VerticalScroll.Value != targetY;
            if (!horizontalChanged && !verticalChanged)
            {
                return;
            }

            panel.AutoScrollPosition = new Point(targetX, targetY);
            panel.Refresh();
        }

        private void EndMiddleMousePan()
        {
            if (!isMiddleMousePanning)
            {
                return;
            }

            isMiddleMousePanning = false;
            pdfViewer.Capture = false;
            this.Cursor = middlePanPreviousCursor ?? Cursors.Default;
            middlePanPreviousCursor = null;
        }

        private void PdfViewer_MouseCaptureChanged(object sender, EventArgs e)
        {
            if (!isMiddleMousePanning)
            {
                return;
            }

            if ((Control.MouseButtons & MouseButtons.Middle) == 0)
            {
                EndMiddleMousePan();
            }
        }

        private string GetShapeTypeDisplayName(VectorShapeType shapeType)
        {
            string lang = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName;
            bool isPl = string.Equals(lang, "pl", StringComparison.OrdinalIgnoreCase);
            bool isDe = string.Equals(lang, "de", StringComparison.OrdinalIgnoreCase);
            switch (shapeType)
            {
                case VectorShapeType.Region:
                    return isPl ? "Region" : isDe ? "Region" : "Region";
                case VectorShapeType.Polyline:
                    return isPl ? "Linia łamana" : isDe ? "Polylinie" : "Polyline";
                case VectorShapeType.Rectangle:
                    return isPl ? "Prostokąt" : isDe ? "Rechteck" : "Rectangle";
                case VectorShapeType.Ellipse:
                    return isPl ? "Elipsa" : isDe ? "Ellipse" : "Ellipse";
                case VectorShapeType.Triangle:
                    return isPl ? "Trójkąt" : isDe ? "Dreieck" : "Triangle";
                case VectorShapeType.Arc:
                    return isPl ? "Łuk" : isDe ? "Bogen" : "Arc";
                default:
                    return shapeType.ToString();
            }
        }

        private string GetShapeToolDialogTitle()
        {
            string lang = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName;
            if (string.Equals(lang, "pl", StringComparison.OrdinalIgnoreCase))
            {
                return "Dodaj kształt";
            }
            if (string.Equals(lang, "de", StringComparison.OrdinalIgnoreCase))
            {
                return "Form hinzufügen";
            }
            return "Add shape";
        }

        private string GetShapeToolInfoText()
        {
            string lang = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName;
            if (string.Equals(lang, "pl", StringComparison.OrdinalIgnoreCase))
            {
                return "Tryb dodawania kształtu aktywny. LPM dodaje punkt, PPM kończy. ALT wymusza symetrię.";
            }
            if (string.Equals(lang, "de", StringComparison.OrdinalIgnoreCase))
            {
                return "Formmodus aktiv. Linksklick fügt Punkte hinzu, Rechtsklick beendet. ALT erzwingt Symmetrie.";
            }
            return "Shape mode active. Left-click adds points, right-click finishes. ALT enforces symmetry.";
        }

        private bool TryGetShapeIconFontFamily(out string familyName)
        {
            familyName = shapeIconPrivateFontFamilyName;
            if (shapeIconPrivateFontChecked)
            {
                return !string.IsNullOrWhiteSpace(familyName);
            }

            shapeIconPrivateFontChecked = true;
            try
            {
                string[] baseDirCandidates = new[]
                {
                    AppDomain.CurrentDomain.BaseDirectory,
                    Application.StartupPath,
                    Environment.CurrentDirectory
                }
                .Where(path => !string.IsNullOrWhiteSpace(path))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToArray();

                var fontPathCandidates = new List<string>();
                foreach (string baseDir in baseDirCandidates)
                {
                    string current = baseDir;
                    for (int depth = 0; depth < 5 && !string.IsNullOrWhiteSpace(current); depth++)
                    {
                        fontPathCandidates.Add(Path.Combine(current, ShapeIconFontFileName));
                        fontPathCandidates.Add(Path.Combine(current, ShapeIconFontLegacyFileName));
                        current = Path.GetDirectoryName(current);
                    }
                }

                string fontPath = fontPathCandidates
                    .Select(path =>
                    {
                        try
                        {
                            return Path.GetFullPath(path);
                        }
                        catch
                        {
                            return null;
                        }
                    })
                    .FirstOrDefault(path => !string.IsNullOrWhiteSpace(path) && File.Exists(path));

                if (!string.IsNullOrWhiteSpace(fontPath))
                {
                    shapeIconPrivateFontCollection.AddFontFile(fontPath);
                    if (shapeIconPrivateFontCollection.Families.Length > 0)
                    {
                        shapeIconPrivateFontPath = fontPath;
                        shapeIconPrivateFontFamilyName = shapeIconPrivateFontCollection.Families[0].Name;
                        familyName = shapeIconPrivateFontFamilyName;
                        return true;
                    }
                }
            }
            catch
            {
                // Ignore and fall back to system fonts.
            }

            familyName = string.Empty;
            return false;
        }

        private static int? GetShapeButtonIconCodePoint(VectorShapeType shapeType)
        {
            switch (shapeType)
            {
                case VectorShapeType.Region:
                    return 0xF0560;
                case VectorShapeType.Polyline:
                    return 0xF0561;
                case VectorShapeType.Rectangle:
                    return 0xF05C6;
                case VectorShapeType.Ellipse:
                    return 0xF0EA1;
                case VectorShapeType.Arc:
                    return 0xF0559;
                case VectorShapeType.Triangle:
                    return 0xF0563;
                default:
                    return null;
            }
        }

        private static Bitmap TrimTransparentBitmap(Bitmap source)
        {
            if (source == null)
            {
                return null;
            }

            int minX = source.Width;
            int minY = source.Height;
            int maxX = -1;
            int maxY = -1;

            for (int y = 0; y < source.Height; y++)
            {
                for (int x = 0; x < source.Width; x++)
                {
                    if (source.GetPixel(x, y).A == 0)
                    {
                        continue;
                    }

                    if (x < minX) minX = x;
                    if (y < minY) minY = y;
                    if (x > maxX) maxX = x;
                    if (y > maxY) maxY = y;
                }
            }

            if (maxX < minX || maxY < minY)
            {
                return new Bitmap(source);
            }

            var rect = new System.Drawing.Rectangle(minX, minY, (maxX - minX) + 1, (maxY - minY) + 1);
            return source.Clone(rect, PixelFormat.Format32bppArgb);
        }

        private bool TryCreateShapeIconBitmap(VectorShapeType shapeType, int pixelSize, out Bitmap bitmap)
        {
            bitmap = null;
            if (pixelSize < 8)
            {
                pixelSize = 8;
            }

            int? codePoint = GetShapeButtonIconCodePoint(shapeType);
            if (!codePoint.HasValue)
            {
                return false;
            }

            if (!TryGetShapeIconFontFamily(out _))
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(shapeIconPrivateFontPath) || !File.Exists(shapeIconPrivateFontPath))
            {
                return false;
            }

            try
            {
                var glyphTypeface = new MediaGlyphTypeface(new Uri(shapeIconPrivateFontPath, UriKind.Absolute));
                if (!glyphTypeface.CharacterToGlyphMap.TryGetValue(codePoint.Value, out ushort glyphIndex))
                {
                    return false;
                }

                double emSize = pixelSize;
                double advance = glyphTypeface.AdvanceWidths[glyphIndex] * emSize;
                double descent = glyphTypeface.Height * emSize;
                double baseline = glyphTypeface.Baseline * emSize;
                int width = Math.Max(16, (int)Math.Ceiling(advance) + 6);
                int height = Math.Max(16, (int)Math.Ceiling(descent) + 6);

                var glyphRun = new System.Windows.Media.GlyphRun(
                    glyphTypeface,
                    0,
                    false,
                    emSize,
                    1.0f,
                    new[] { glyphIndex },
                    new WpfPoint(3, baseline + 1),
                    new[] { advance },
                    null,
                    null,
                    null,
                    null,
                    null,
                    null);

                var visual = new MediaDrawingVisual();
                using (System.Windows.Media.DrawingContext dc = visual.RenderOpen())
                {
                    dc.DrawGlyphRun(MediaBrushes.Black, glyphRun);
                }

                var renderTarget = new MediaRenderTargetBitmap(width, height, 96, 96, MediaPixelFormats.Pbgra32);
                renderTarget.Render(visual);

                using (var ms = new MemoryStream())
                {
                    var encoder = new MediaPngBitmapEncoder();
                    encoder.Frames.Add(MediaBitmapFrame.Create(renderTarget));
                    encoder.Save(ms);
                    ms.Position = 0;
                    using (var loaded = new Bitmap(ms))
                    {
                        using (var rawBitmap = new Bitmap(loaded))
                        {
                            bitmap = TrimTransparentBitmap(rawBitmap);
                        }
                    }
                }

                return bitmap != null;
            }
            catch
            {
                bitmap?.Dispose();
                bitmap = null;
                return false;
            }
        }

        private bool TryPromptShapeDefaults(
            out VectorShapeDefaults selectedDefaults,
            VectorShapeDefaults initialDefaults = null,
            bool lockShapeType = false)
        {
            selectedDefaults = null;
            VectorShapeDefaults sourceDefaults = initialDefaults ?? activeVectorShapeDefaults;
            VectorShapeDefaults working = sourceDefaults?.Clone() ?? VectorShapeDefaults.CreateDefault();
            VectorShapeType selectedShape = working.ShapeType;
            string lang = (Resources.Culture ?? CultureInfo.CurrentUICulture).TwoLetterISOLanguageName;
            bool isPl = string.Equals(lang, "pl", StringComparison.OrdinalIgnoreCase);
            bool isDe = string.Equals(lang, "de", StringComparison.OrdinalIgnoreCase);

            using (var prompt = new Form())
            {
                prompt.Text = GetShapeToolDialogTitle();
                prompt.StartPosition = FormStartPosition.CenterParent;
                prompt.FormBorderStyle = FormBorderStyle.FixedDialog;
                prompt.MinimizeBox = false;
                prompt.MaximizeBox = false;
                prompt.ShowInTaskbar = false;
                prompt.Width = 620;
                prompt.Height = 340;

                var shapeButtons = new Dictionary<VectorShapeType, Button>();

                var labelShapes = new Label
                {
                    Left = 12,
                    Top = 12,
                    Width = 560,
                    Text = isPl ? "Kształt:" : isDe ? "Form:" : "Shape:"
                };

                var shapesPanel = new FlowLayoutPanel
                {
                    Left = 12,
                    Top = 34,
                    Width = 584,
                    Height = 74,
                    WrapContents = false,
                    Padding = new Padding(0)
                };
                Action refreshVectorStyleControls = null;

                string ignoredShapeIconFamily;
                bool useMaterialIcons = TryGetShapeIconFontFamily(out ignoredShapeIconFamily);
                var shapeButtonToolTip = new ToolTip();
                var shapeButtonImages = new List<Image>();
                prompt.Disposed += (_, __) => shapeButtonToolTip?.Dispose();
                prompt.Disposed += (_, __) =>
                {
                    foreach (var img in shapeButtonImages)
                    {
                        img?.Dispose();
                    }
                };
                foreach (VectorShapeType shapeType in Enum.GetValues(typeof(VectorShapeType)))
                {
                    var button = new Button
                    {
                        Width = 60,
                        Height = 60,
                        Margin = new Padding(2),
                        Padding = new Padding(0),
                        Text = string.Empty,
                        TextAlign = ContentAlignment.MiddleCenter,
                        TextImageRelation = TextImageRelation.Overlay,
                        Tag = shapeType,
                        UseCompatibleTextRendering = true
                    };
                    shapeButtonToolTip.SetToolTip(button, GetShapeTypeDisplayName(shapeType));
                    if (useMaterialIcons && TryCreateShapeIconBitmap(shapeType, 30, out Bitmap iconBitmap))
                    {
                        button.Image = iconBitmap;
                        button.ImageAlign = ContentAlignment.MiddleCenter;
                        shapeButtonImages.Add(iconBitmap);
                    }
                    else
                    {
                        button.Text = GetShapeTypeDisplayName(shapeType);
                    }

                    button.Click += (_, __) =>
                    {
                        if (lockShapeType)
                        {
                            return;
                        }

                        selectedShape = shapeType;
                        foreach (var pair in shapeButtons)
                        {
                            pair.Value.BackColor = pair.Key == selectedShape
                                ? System.Drawing.Color.FromArgb(220, 240, 255)
                                : SystemColors.Control;
                        }
                        refreshVectorStyleControls?.Invoke();
                    };

                    shapeButtons[shapeType] = button;
                    shapesPanel.Controls.Add(button);
                }

                var labelStrokeColor = new Label { Left = 12, Top = 120, Width = 120, Text = isPl ? "Kolor linii:" : isDe ? "Linienfarbe:" : "Line color:" };
                System.Drawing.Color strokeBaseColor = System.Drawing.Color.FromArgb(working.StrokeColorArgb);
                var buttonStrokeColor = new Button
                {
                    Left = 140,
                    Top = 116,
                    Width = 140,
                    Height = 26,
                    BackColor = System.Drawing.Color.FromArgb(strokeBaseColor.R, strokeBaseColor.G, strokeBaseColor.B)
                };
                buttonStrokeColor.Click += (_, __) =>
                {
                    using (var dlg = new ColorDialog())
                    {
                        dlg.Color = buttonStrokeColor.BackColor;
                        dlg.FullOpen = true;
                        if (dlg.ShowDialog(this) == DialogResult.OK)
                        {
                            buttonStrokeColor.BackColor = dlg.Color;
                        }
                    }
                };
                var checkNoStrokeColor = new CheckBox
                {
                    Left = 140,
                    Top = 146,
                    Width = 180,
                    Text = isPl ? "Brak koloru linii" : isDe ? "Keine Linienfarbe" : "No line color",
                    Checked = !HasVisibleVectorColor(working.StrokeColorArgb)
                };

                var labelStrokeWidth = new Label { Left = 300, Top = 120, Width = 95, Text = isPl ? "Grubość:" : isDe ? "Stärke:" : "Width:" };
                var numericStrokeWidth = new NumericUpDown
                {
                    Left = 398,
                    Top = 116,
                    Width = 70,
                    DecimalPlaces = 1,
                    Minimum = 1,
                    Maximum = 24,
                    Increment = 0.5m,
                    Value = (decimal)NormalizeVectorStrokeWidth(working.StrokeWidth)
                };

                var labelStrokeStyle = new Label { Left = 482, Top = 120, Width = 60, Text = isPl ? "Linia:" : isDe ? "Stil:" : "Style:" };
                var comboStrokeStyle = new ComboBox
                {
                    Left = 540,
                    Top = 116,
                    Width = 56,
                    DropDownStyle = ComboBoxStyle.DropDownList
                };
                comboStrokeStyle.DropDownWidth = 170;
                comboStrokeStyle.Items.Add(isPl ? "Ciągła" : isDe ? "Durchgezogen" : "Solid");
                comboStrokeStyle.Items.Add(isPl ? "Przerywana" : isDe ? "Gestrichelt" : "Dash");
                comboStrokeStyle.Items.Add(isPl ? "Kropkowana" : isDe ? "Gepunktet" : "Dot");
                comboStrokeStyle.Items.Add(isPl ? "Kreska-kropka" : isDe ? "Strich-Punkt" : "Dash-dot");
                comboStrokeStyle.Items.Add(isPl ? "Kreska-kropka-kropka" : isDe ? "Strich-Punkt-Punkt" : "Dash-dot-dot");
                switch (working.StrokeKind)
                {
                    case VectorShapeStrokeKind.Dash:
                        comboStrokeStyle.SelectedIndex = 1;
                        break;
                    case VectorShapeStrokeKind.Dot:
                        comboStrokeStyle.SelectedIndex = 2;
                        break;
                    case VectorShapeStrokeKind.DashDot:
                        comboStrokeStyle.SelectedIndex = 3;
                        break;
                    case VectorShapeStrokeKind.DashDotDot:
                        comboStrokeStyle.SelectedIndex = 4;
                        break;
                    default:
                        comboStrokeStyle.SelectedIndex = 0;
                        break;
                }

                var labelFillColor = new Label { Left = 12, Top = 184, Width = 120, Text = isPl ? "Kolor wypełnienia:" : isDe ? "Füllfarbe:" : "Fill color:" };
                System.Drawing.Color fillBaseColor = System.Drawing.Color.FromArgb(working.FillColorArgb);
                var buttonFillColor = new Button
                {
                    Left = 140,
                    Top = 180,
                    Width = 140,
                    Height = 26,
                    BackColor = System.Drawing.Color.FromArgb(fillBaseColor.R, fillBaseColor.G, fillBaseColor.B)
                };
                buttonFillColor.Click += (_, __) =>
                {
                    using (var dlg = new ColorDialog())
                    {
                        dlg.Color = buttonFillColor.BackColor;
                        dlg.FullOpen = true;
                        if (dlg.ShowDialog(this) == DialogResult.OK)
                        {
                            buttonFillColor.BackColor = dlg.Color;
                        }
                    }
                };
                var checkNoFillColor = new CheckBox
                {
                    Left = 140,
                    Top = 210,
                    Width = 200,
                    Text = isPl ? "Brak koloru wypełnienia" : isDe ? "Keine Füllfarbe" : "No fill color",
                    Checked = !HasVisibleVectorColor(working.FillColorArgb) || NormalizeVectorFillOpacity(working.FillOpacity) <= 0f
                };

                var labelFillOpacity = new Label { Left = 300, Top = 184, Width = 95, Text = isPl ? "Wypełnienie (%):" : isDe ? "Füllung (%):" : "Fill (%):" };
                var numericFillOpacity = new NumericUpDown
                {
                    Left = 398,
                    Top = 180,
                    Width = 70,
                    DecimalPlaces = 0,
                    Minimum = 0,
                    Maximum = 100,
                    Increment = 5,
                    Value = (decimal)Math.Round(NormalizeVectorFillOpacity(working.FillOpacity) * 100f)
                };
                checkNoStrokeColor.CheckedChanged += (_, __) => refreshVectorStyleControls?.Invoke();
                checkNoFillColor.CheckedChanged += (_, __) => refreshVectorStyleControls?.Invoke();
                refreshVectorStyleControls = () =>
                {
                    bool supportsFill = ShapeTypeSupportsFill(selectedShape);
                    bool hasStroke = !checkNoStrokeColor.Checked;
                    bool hasFill = supportsFill && !checkNoFillColor.Checked;

                    buttonStrokeColor.Enabled = hasStroke;
                    labelStrokeWidth.Enabled = hasStroke;
                    numericStrokeWidth.Enabled = hasStroke;
                    labelStrokeStyle.Enabled = hasStroke;
                    comboStrokeStyle.Enabled = hasStroke;

                    labelFillColor.Enabled = supportsFill;
                    checkNoFillColor.Enabled = supportsFill;
                    buttonFillColor.Enabled = hasFill;
                    labelFillOpacity.Enabled = hasFill;
                    numericFillOpacity.Enabled = hasFill;
                };

                var buttonOk = new Button { Left = 364, Top = 252, Width = 110, Text = "OK", DialogResult = DialogResult.OK };
                var buttonCancel = new Button { Left = 486, Top = 252, Width = 110, Text = isPl ? "Anuluj" : isDe ? "Abbrechen" : "Cancel", DialogResult = DialogResult.Cancel };

                prompt.Controls.Add(labelShapes);
                prompt.Controls.Add(shapesPanel);
                prompt.Controls.Add(labelStrokeColor);
                prompt.Controls.Add(buttonStrokeColor);
                prompt.Controls.Add(labelStrokeWidth);
                prompt.Controls.Add(numericStrokeWidth);
                prompt.Controls.Add(labelStrokeStyle);
                prompt.Controls.Add(comboStrokeStyle);
                prompt.Controls.Add(checkNoStrokeColor);
                prompt.Controls.Add(labelFillColor);
                prompt.Controls.Add(buttonFillColor);
                prompt.Controls.Add(labelFillOpacity);
                prompt.Controls.Add(numericFillOpacity);
                prompt.Controls.Add(checkNoFillColor);
                prompt.Controls.Add(buttonOk);
                prompt.Controls.Add(buttonCancel);
                prompt.AcceptButton = buttonOk;
                prompt.CancelButton = buttonCancel;

                if (shapeButtons.TryGetValue(selectedShape, out Button selectedButton))
                {
                    selectedButton.PerformClick();
                }

                if (lockShapeType)
                {
                    foreach (var pair in shapeButtons)
                    {
                        bool isSelected = pair.Key == selectedShape;
                        pair.Value.Enabled = isSelected;
                        pair.Value.BackColor = isSelected
                            ? System.Drawing.Color.FromArgb(220, 240, 255)
                            : SystemColors.Control;
                    }
                }
                refreshVectorStyleControls?.Invoke();

                if (prompt.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                working.ShapeType = selectedShape;
                bool supportsFillForShape = ShapeTypeSupportsFill(selectedShape);
                System.Drawing.Color selectedStroke = buttonStrokeColor.BackColor;
                working.StrokeColorArgb = checkNoStrokeColor.Checked
                    ? System.Drawing.Color.FromArgb(0, selectedStroke.R, selectedStroke.G, selectedStroke.B).ToArgb()
                    : System.Drawing.Color.FromArgb(255, selectedStroke.R, selectedStroke.G, selectedStroke.B).ToArgb();
                working.StrokeWidth = NormalizeVectorStrokeWidth((float)numericStrokeWidth.Value);
                System.Drawing.Color selectedFill = buttonFillColor.BackColor;
                bool noFill = !supportsFillForShape || checkNoFillColor.Checked;
                working.FillColorArgb = noFill
                    ? System.Drawing.Color.FromArgb(0, selectedFill.R, selectedFill.G, selectedFill.B).ToArgb()
                    : System.Drawing.Color.FromArgb(255, selectedFill.R, selectedFill.G, selectedFill.B).ToArgb();
                working.FillOpacity = noFill
                    ? 0f
                    : NormalizeVectorFillOpacity((float)(numericFillOpacity.Value / 100m));
                switch (comboStrokeStyle.SelectedIndex)
                {
                    case 1:
                        working.StrokeKind = VectorShapeStrokeKind.Dash;
                        break;
                    case 2:
                        working.StrokeKind = VectorShapeStrokeKind.Dot;
                        break;
                    case 3:
                        working.StrokeKind = VectorShapeStrokeKind.DashDot;
                        break;
                    case 4:
                        working.StrokeKind = VectorShapeStrokeKind.DashDotDot;
                        break;
                    default:
                        working.StrokeKind = VectorShapeStrokeKind.Solid;
                        break;
                }

                selectedDefaults = working;
                return true;
            }
        }

        private void BeginVectorShapeCreation(VectorShapeDefaults selectedDefaults)
        {
            if (selectedDefaults == null)
            {
                return;
            }

            activeVectorShapeDefaults = selectedDefaults.Clone();
            activeVectorShapeType = activeVectorShapeDefaults.ShapeType;
            isVectorShapeCreationMode = true;
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;
            this.Cursor = Cursors.Cross;
            ShowInfoMessage(GetShapeToolInfoText());
            pdfViewer.Invalidate();
        }

        private void EndVectorShapeCreationMode(bool keepDefaults = true)
        {
            isVectorShapeCreationMode = false;
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;
            this.Cursor = Cursors.Default;
            if (!keepDefaults)
            {
                activeVectorShapeDefaults = VectorShapeDefaults.CreateDefault();
                activeVectorShapeType = activeVectorShapeDefaults.ShapeType;
            }
        }

        private bool TryFinalizeVectorShapeDraft()
        {
            int requiredPoints = GetRequiredPointsForShape(activeVectorShapeType);
            if (vectorShapeDraftPoints.Count < requiredPoints)
            {
                return false;
            }

            var shape = new VectorShapeObject
            {
                Id = Guid.NewGuid().ToString("N"),
                PageNumber = currentPage,
                ShapeType = activeVectorShapeType.ToString(),
                Points = vectorShapeDraftPoints.ToList(),
                StrokeColorArgb = activeVectorShapeDefaults.StrokeColorArgb,
                StrokeWidth = NormalizeVectorStrokeWidth(activeVectorShapeDefaults.StrokeWidth),
                FillColorArgb = activeVectorShapeDefaults.FillColorArgb,
                FillOpacity = NormalizeVectorFillOpacity(activeVectorShapeDefaults.FillOpacity),
                StrokeStyle = activeVectorShapeDefaults.StrokeKind.ToString(),
                CreatedAtUtc = DateTime.UtcNow,
                UpdatedAtUtc = DateTime.UtcNow
            };
            NormalizeVectorShape(shape);

            vectorShapes.Add(shape);
            vectorShapeDraftPoints.Clear();
            vectorShapeDraftHoverActive = false;

            PageItemStatus status = allPageStatuses[currentPage - 1];
            status.HasObjects = true;
            if ((string)filterComboBox.SelectedItem == allComboItem)
            {
                ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                pagesListView.Invalidate(currentItem.Bounds);
            }
            else
            {
                ApplyFilter((string)filterComboBox.SelectedItem);
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
            return true;
        }

        private static float DistanceBetweenPoints(PointF a, PointF b)
        {
            float dx = a.X - b.X;
            float dy = a.Y - b.Y;
            return (float)Math.Sqrt((dx * dx) + (dy * dy));
        }

        private void OnMouseDown(object sender, MouseEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            if (e.Button == MouseButtons.Middle)
            {
                isDrawing = false;
                isMarkerCtrlBoxMode = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetGroupMoveState();
                currentSelection = RectangleF.Empty;
                isClickOnIcon = false;
                clickedIconType = IconType.None;
                annotationForIcon = null;
                ClearRasterIconClickState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                TryBeginMiddleMousePan();
                return;
            }

            if (isVectorShapeCreationMode)
            {
                if (!EnsureCurrentPageEditable(true))
                {
                    EndVectorShapeCreationMode();
                    return;
                }

                PointF rawDocPoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                PointF docPoint = NormalizeVectorShapeDraftInputPoint(rawDocPoint);
                int requiredPoints = GetRequiredPointsForShape(activeVectorShapeType);
                bool isFreeformShape = activeVectorShapeType == VectorShapeType.Polyline || activeVectorShapeType == VectorShapeType.Region;
                if (e.Button == MouseButtons.Left)
                {
                    if (isFreeformShape && e.Clicks > 1)
                    {
                        if (vectorShapeDraftPoints.Count == 0 || DistanceBetweenPoints(vectorShapeDraftPoints.Last(), docPoint) > 0.5f)
                        {
                            vectorShapeDraftPoints.Add(docPoint);
                        }
                        TryFinalizeVectorShapeDraft();
                        pdfViewer.Invalidate();
                        return;
                    }

                    vectorShapeDraftPoints.Add(docPoint);
                    vectorShapeDraftHoverPoint = docPoint;
                    vectorShapeDraftHoverActive = true;
                    if (!isFreeformShape && vectorShapeDraftPoints.Count >= requiredPoints)
                    {
                        TryFinalizeVectorShapeDraft();
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (e.Button == MouseButtons.Right)
                {
                    if (!TryFinalizeVectorShapeDraft())
                    {
                        if (vectorShapeDraftPoints.Count > 0)
                        {
                            vectorShapeDraftPoints.Clear();
                            vectorShapeDraftHoverActive = false;
                        }
                        else
                        {
                            EndVectorShapeCreationMode();
                        }
                    }

                    pdfViewer.Invalidate();
                    return;
                }
            }

            // Reset icon click flag
            isClickOnIcon = false;
            clickedIconType = IconType.None;
            annotationForIcon = null;
            ClearRasterIconClickState();
            ClearArrowIconClickState();
            ClearVectorIconClickState();
            rasterMouseActionInProgress = false;
            arrowMouseActionInProgress = false;
            vectorMouseActionInProgress = false;
            if (IsCurrentPageMarkedForDeletion() && (e.Button == MouseButtons.Left || e.Button == MouseButtons.Right))
            {
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                return;
            }

            if (e.Button == MouseButtons.Right)
            {
                isDrawing = false;
                startPoint = e.Location;
            }
            else if (e.Button == MouseButtons.Left)
            {
                startPoint = e.Location;
                isMarkerCtrlBoxMode = false;

                float dpiX;
                float dpiY;
                using (Graphics g = pdfViewer.CreateGraphics())
                {
                    dpiX = g.DpiX;
                    dpiY = g.DpiY;
                }

                bool additiveSelection = (Control.ModifierKeys & Keys.Control) == Keys.Control;
                if (additiveSelection)
                {
                    if (TryToggleGroupSelectionAtPoint(e.Location, dpiX, dpiY))
                    {
                        ResetRasterInteractionState();
                        ResetArrowInteractionState();
                        ResetVectorInteractionState();
                        selectedVectorShape = null;
                        ResetGroupMoveState();
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        textMoveMouseOffset = PointF.Empty;
                        this.Cursor = Cursors.Default;
                        pdfViewer.Invalidate();
                        return;
                    }
                }
                else if (GetGroupSelectionCount() > 0)
                {
                    if (TryBeginGroupMove(e.Location, dpiX, dpiY))
                    {
                        ResetRasterInteractionState();
                        ResetArrowInteractionState();
                        ResetVectorInteractionState();
                        selectedVectorShape = null;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        textMoveMouseOffset = PointF.Empty;
                        pdfViewer.Invalidate();
                        return;
                    }

                    ClearGroupSelection();
                    ResetGroupMoveState();
                }

                if (TryHandleAnnotationIconMouseDown(e.Location, dpiX, dpiY))
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    isDrawing = false;
                    isMoving = false;
                    annotationToMove = null;
                    pdfViewer.Invalidate();
                    return;
                }

                TextAnnotation hitAnnotation = textAnnotations
                    .Where(block => block.PageNumber == currentPage)
                    .Reverse()
                    .FirstOrDefault(block => GetAnnotationScreenRect(block, dpiX, dpiY).Contains(e.Location));

                if (hitAnnotation != null)
                {
                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedRasterObject = null;
                    ResetRasterInteractionState();
                    ClearGroupSelection();
                    selectedTextAnnotation = hitAnnotation;
                    isDrawing = false;

                    if (!hitAnnotation.AnnotationIsLocked)
                    {
                        annotationToMove = hitAnnotation;
                        isMoving = true;
                        PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                        textMoveMouseOffset = new PointF(
                            mouseDoc.X - hitAnnotation.AnnotationBounds.X,
                            mouseDoc.Y - hitAnnotation.AnnotationBounds.Y);
                        this.Cursor = Cursors.SizeAll;
                    }
                    else
                    {
                        annotationToMove = null;
                        isMoving = false;
                        textMoveMouseOffset = PointF.Empty;
                        this.Cursor = Cursors.Default;
                    }
                }
                else
                {
                    if (TryHandleArrowIconMouseDown(e.Location))
                    {
                        selectedTextAnnotation = null;
                        selectedRasterObject = null;
                        ResetRasterInteractionState();
                        selectedVectorShape = null;
                        ResetVectorInteractionState();
                        ClearVectorIconClickState();
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryHandleVectorIconMouseDown(e.Location))
                    {
                        selectedArrowObject = null;
                        ResetArrowInteractionState();
                        ClearArrowIconClickState();
                        selectedRasterObject = null;
                        ResetRasterInteractionState();
                        ClearRasterIconClickState();
                        selectedTextAnnotation = null;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryHandleVectorShapeMouseDown(e.Location))
                    {
                        selectedArrowObject = null;
                        ResetArrowInteractionState();
                        ClearArrowIconClickState();
                        selectedRasterObject = null;
                        ResetRasterInteractionState();
                        ClearRasterIconClickState();
                        selectedTextAnnotation = null;
                        arrowMouseActionInProgress = false;
                        rasterMouseActionInProgress = false;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryHandleArrowMouseDown(e.Location))
                    {
                        selectedTextAnnotation = null;
                        selectedRasterObject = null;
                        ResetRasterInteractionState();
                        selectedVectorShape = null;
                        ResetVectorInteractionState();
                        ClearArrowIconClickState();
                        arrowMouseActionInProgress = true;
                        arrowInteractionChanged = false;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryHandleRasterIconMouseDown(e.Location))
                    {
                        selectedArrowObject = null;
                        ResetArrowInteractionState();
                        ClearArrowIconClickState();
                        selectedVectorShape = null;
                        ResetVectorInteractionState();
                        selectedTextAnnotation = null;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    if (TryHandleRasterMouseDown(e.Location))
                    {
                        selectedArrowObject = null;
                        ResetArrowInteractionState();
                        ClearArrowIconClickState();
                        selectedVectorShape = null;
                        ResetVectorInteractionState();
                        selectedTextAnnotation = null;
                        rasterMouseActionInProgress = true;
                        isDrawing = false;
                        isMoving = false;
                        annotationToMove = null;
                        pdfViewer.Invalidate();
                        return;
                    }

                    selectedArrowObject = null;
                    ResetArrowInteractionState();
                    ClearArrowIconClickState();
                    selectedVectorShape = null;
                    ResetVectorInteractionState();
                    selectedTextAnnotation = null;
                    annotationToMove = null;
                    isMoving = false;
                    textMoveMouseOffset = PointF.Empty;
                    isDrawing = true;
                    currentSelection = new System.Drawing.RectangleF(startPoint, Size.Empty);
                }
                pdfViewer.Invalidate();
            }
        }

        private void OnMouseMove(object sender, MouseEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            if (isMiddleMousePanning)
            {
                UpdateMiddleMousePan();
                return;
            }

            if (IsCurrentPageMarkedForDeletion())
            {
                isDrawing = false;
                isMoving = false;
                annotationToMove = null;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                return;
            }

            if (isVectorShapeCreationMode)
            {
                PointF rawHover = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                vectorShapeDraftHoverPoint = NormalizeVectorShapeDraftInputPoint(rawHover);
                vectorShapeDraftHoverActive = true;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingObjectGroup)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - groupMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - groupMoveStartMouseDoc.Y;

                if (snapToGridEnabled)
                {
                    float snappedLeft = SnapValueToGrid(groupMoveInitialBounds.X + dx, SnapGridStep);
                    float snappedTop = SnapValueToGrid(groupMoveInitialBounds.Y + dy, SnapGridStep);
                    dx = snappedLeft - groupMoveInitialBounds.X;
                    dy = snappedTop - groupMoveInitialBounds.Y;
                }

                dx = Math.Max(groupMoveMinDx, Math.Min(groupMoveMaxDx, dx));
                dy = Math.Max(groupMoveMinDy, Math.Min(groupMoveMaxDy, dy));
                if (Math.Abs(dx) > 0.001f || Math.Abs(dy) > 0.001f)
                {
                    groupMoveChanged = true;
                }

                foreach (GroupMoveEntry entry in groupMoveEntries)
                {
                    switch (entry.Type)
                    {
                        case GroupMoveObjectType.Text:
                            if (entry.Text != null)
                            {
                                entry.Text.AnnotationBounds = new RectangleF(
                                    entry.Bounds.X + dx,
                                    entry.Bounds.Y + dy,
                                    entry.Bounds.Width,
                                    entry.Bounds.Height);
                            }
                            break;
                        case GroupMoveObjectType.Raster:
                            if (entry.Raster != null)
                            {
                                entry.Raster.Bounds = new RectangleF(
                                    entry.Bounds.X + dx,
                                    entry.Bounds.Y + dy,
                                    entry.Bounds.Width,
                                    entry.Bounds.Height);
                                entry.Raster.UpdatedAtUtc = DateTime.UtcNow;
                            }
                            break;
                        case GroupMoveObjectType.Arrow:
                            if (entry.Arrow != null)
                            {
                                entry.Arrow.Start = new PointF(entry.Start.X + dx, entry.Start.Y + dy);
                                entry.Arrow.End = new PointF(entry.End.X + dx, entry.End.Y + dy);
                                entry.Arrow.UpdatedAtUtc = DateTime.UtcNow;
                            }
                            break;
                    }
                }

                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isAdjustingArrowHandle && arrowObjectToAdjust != null && arrowHandleType != ArrowHandleType.None)
            {
                PointF mousePoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                mousePoint = SnapPointToGrid(mousePoint);
                if (arrowHandleType == ArrowHandleType.Start)
                {
                    arrowObjectToAdjust.Start = mousePoint;
                }
                else if (arrowHandleType == ArrowHandleType.End)
                {
                    arrowObjectToAdjust.End = mousePoint;
                }

                ConstrainArrowToPage(arrowObjectToAdjust);
                arrowObjectToAdjust.Thickness = NormalizeArrowThickness(arrowObjectToAdjust.Thickness);
                arrowObjectToAdjust.HeadLength = NormalizeArrowHeadLength(arrowObjectToAdjust.HeadLength);
                arrowObjectToAdjust.HeadWidth = NormalizeArrowHeadWidth(arrowObjectToAdjust.HeadWidth);
                arrowObjectToAdjust.UpdatedAtUtc = DateTime.UtcNow;
                arrowInteractionChanged = true;
                this.Cursor = Cursors.Hand;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingArrowObject && arrowObjectToMove != null)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - arrowMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - arrowMoveStartMouseDoc.Y;

                if (snapToGridEnabled)
                {
                    float snappedStartX = SnapValueToGrid(arrowMoveInitialStart.X + dx, SnapGridStep);
                    float snappedStartY = SnapValueToGrid(arrowMoveInitialStart.Y + dy, SnapGridStep);
                    dx = snappedStartX - arrowMoveInitialStart.X;
                    dy = snappedStartY - arrowMoveInitialStart.Y;
                }

                var pageSize = GetPageSizeWithOffset(arrowObjectToMove.PageNumber);
                if (pageSize.Width > 0f && pageSize.Height > 0f)
                {
                    float minBaseX = Math.Min(arrowMoveInitialStart.X, arrowMoveInitialEnd.X);
                    float maxBaseX = Math.Max(arrowMoveInitialStart.X, arrowMoveInitialEnd.X);
                    float minBaseY = Math.Min(arrowMoveInitialStart.Y, arrowMoveInitialEnd.Y);
                    float maxBaseY = Math.Max(arrowMoveInitialStart.Y, arrowMoveInitialEnd.Y);

                    float minDx = -minBaseX;
                    float maxDx = pageSize.Width - maxBaseX;
                    float minDy = -minBaseY;
                    float maxDy = pageSize.Height - maxBaseY;

                    dx = Math.Max(minDx, Math.Min(maxDx, dx));
                    dy = Math.Max(minDy, Math.Min(maxDy, dy));
                }

                PointF nextStart = new PointF(arrowMoveInitialStart.X + dx, arrowMoveInitialStart.Y + dy);
                PointF nextEnd = new PointF(arrowMoveInitialEnd.X + dx, arrowMoveInitialEnd.Y + dy);
                arrowObjectToMove.Start = nextStart;
                arrowObjectToMove.End = nextEnd;
                arrowObjectToMove.UpdatedAtUtc = DateTime.UtcNow;
                arrowInteractionChanged = true;
                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (isRotatingRasterObject && rasterObjectToRotate != null)
            {
                PointF center = GetRasterObjectScreenCenter(rasterObjectToRotate);
                float currentAngle = GetAngleDegrees(center, e.Location);
                float delta = NormalizeAngleDelta(currentAngle - rasterRotationStartAngle);
                rasterObjectToRotate.Rotation = NormalizeRotation(rasterRotationStartValue + (int)Math.Round(delta));
                ConstrainRasterObjectToPage(rasterObjectToRotate);
                rasterObjectToRotate.UpdatedAtUtc = DateTime.UtcNow;
                pdfViewer.Invalidate();
                return;
            }

            if (isResizingRasterObject && rasterObjectToResize != null && rasterResizeHandle != RasterResizeHandleType.None)
            {
                this.Cursor = GetCursorForRasterResizeHandle(rasterResizeHandle, rasterObjectToResize.Rotation);
                PointF mousePoint = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                if (snapToGridEnabled)
                {
                    mousePoint = SnapPointToGrid(mousePoint);
                }
                float minWidth = 10f;
                float minHeight = 10f;
                RectangleF bounds = rasterObjectToResize.Bounds;
                bool cornerHandle =
                    rasterResizeHandle == RasterResizeHandleType.TopLeft ||
                    rasterResizeHandle == RasterResizeHandleType.TopRight ||
                    rasterResizeHandle == RasterResizeHandleType.BottomRight ||
                    rasterResizeHandle == RasterResizeHandleType.BottomLeft;
                bool symmetricResize = (Control.ModifierKeys & Keys.Alt) == Keys.Alt;

                if (symmetricResize)
                {
                    PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
                    PointF deltaPoint = new PointF(mousePoint.X - center.X, mousePoint.Y - center.Y);
                    PointF local = RotateVector(deltaPoint, -NormalizeRotation(rasterObjectToResize.Rotation));
                    float newWidth = bounds.Width;
                    float newHeight = bounds.Height;

                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            newWidth = Math.Max(minWidth, 2f * Math.Abs(local.X));
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            newHeight = Math.Max(minHeight, 2f * Math.Abs(local.Y));
                            break;
                        default:
                            newWidth = Math.Max(minWidth, 2f * Math.Abs(local.X));
                            newHeight = Math.Max(minHeight, 2f * Math.Abs(local.Y));
                            break;
                    }

                    if (cornerHandle)
                    {
                        float aspect = bounds.Height <= 0f ? 1f : (bounds.Width / bounds.Height);
                        if (aspect <= 0f)
                        {
                            aspect = 1f;
                        }

                        float widthFromHeight = newHeight * aspect;
                        float heightFromWidth = newWidth / aspect;
                        if (widthFromHeight > newWidth)
                        {
                            newWidth = widthFromHeight;
                        }
                        else
                        {
                            newHeight = heightFromWidth;
                        }
                    }

                    rasterObjectToResize.Bounds = new RectangleF(
                        center.X - (newWidth / 2f),
                        center.Y - (newHeight / 2f),
                        newWidth,
                        newHeight);
                }
                else
                {
                    RectangleF baseBounds = HasPositiveSize(rasterResizeStartBounds) ? rasterResizeStartBounds : bounds;
                    int baseRotation = NormalizeRotation(rasterResizeStartRotation);
                    if (baseRotation != NormalizeRotation(rasterObjectToResize.Rotation))
                    {
                        baseRotation = NormalizeRotation(rasterObjectToResize.Rotation);
                    }

                    float width = baseBounds.Width;
                    float height = baseBounds.Height;
                    PointF sign = GetRasterResizeSign(rasterResizeHandle);
                    PointF anchorWorld = rasterResizeAnchorWorld;
                    if (!HasPositiveSize(rasterResizeStartBounds))
                    {
                        RasterResizeHandleType oppositeHandle = GetOppositeRasterResizeHandle(rasterResizeHandle);
                        anchorWorld = GetRasterResizeHandleWorldPoint(baseBounds, baseRotation, oppositeHandle);
                    }

                    PointF anchorLocalAbs = RotateVector(anchorWorld, -baseRotation);
                    PointF dragLocalAbs = RotateVector(mousePoint, -baseRotation);

                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            dragLocalAbs.Y = anchorLocalAbs.Y;
                            width = Math.Max(minWidth, Math.Abs(dragLocalAbs.X - anchorLocalAbs.X));
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            dragLocalAbs.X = anchorLocalAbs.X;
                            height = Math.Max(minHeight, Math.Abs(dragLocalAbs.Y - anchorLocalAbs.Y));
                            break;
                        default:
                            width = Math.Max(minWidth, Math.Abs(dragLocalAbs.X - anchorLocalAbs.X));
                            height = Math.Max(minHeight, Math.Abs(dragLocalAbs.Y - anchorLocalAbs.Y));
                            break;
                    }

                    if (cornerHandle)
                    {
                        float aspect = baseBounds.Height <= 0f ? 1f : (baseBounds.Width / baseBounds.Height);
                        if (aspect <= 0f)
                        {
                            aspect = 1f;
                        }

                        float widthFromHeight = height * aspect;
                        float heightFromWidth = width / aspect;
                        if (widthFromHeight > width)
                        {
                            width = widthFromHeight;
                        }
                        else
                        {
                            height = heightFromWidth;
                        }
                    }

                    float dragX = anchorLocalAbs.X;
                    float dragY = anchorLocalAbs.Y;
                    switch (rasterResizeHandle)
                    {
                        case RasterResizeHandleType.Left:
                        case RasterResizeHandleType.Right:
                            dragX = anchorLocalAbs.X + (sign.X * width);
                            dragY = anchorLocalAbs.Y;
                            break;
                        case RasterResizeHandleType.Top:
                        case RasterResizeHandleType.Bottom:
                            dragX = anchorLocalAbs.X;
                            dragY = anchorLocalAbs.Y + (sign.Y * height);
                            break;
                        default:
                            dragX = anchorLocalAbs.X + (sign.X * width);
                            dragY = anchorLocalAbs.Y + (sign.Y * height);
                            break;
                    }

                    PointF centerLocalAbs = new PointF(
                        (anchorLocalAbs.X + dragX) / 2f,
                        (anchorLocalAbs.Y + dragY) / 2f);
                    PointF centerWorld = RotateVector(centerLocalAbs, baseRotation);

                    rasterObjectToResize.Bounds = new RectangleF(
                        centerWorld.X - (width / 2f),
                        centerWorld.Y - (height / 2f),
                        width,
                        height);
                }

                ConstrainRasterObjectToPage(rasterObjectToResize);
                rasterObjectToResize.UpdatedAtUtc = DateTime.UtcNow;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingRasterObject && rasterObjectToMove != null)
            {
                RectangleF bounds = rasterObjectToMove.Bounds;
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float newX = mouseDoc.X - rasterMoveMouseOffset.X;
                float newY = mouseDoc.Y - rasterMoveMouseOffset.Y;
                if (snapToGridEnabled)
                {
                    newX = SnapValueToGrid(newX, SnapGridStep);
                    newY = SnapValueToGrid(newY, SnapGridStep);
                }
                rasterObjectToMove.Bounds = new RectangleF(newX, newY, bounds.Width, bounds.Height);
                ConstrainRasterObjectToPage(rasterObjectToMove);
                rasterObjectToMove.UpdatedAtUtc = DateTime.UtcNow;
                pdfViewer.Invalidate();
                return;
            }

            if (isMovingVectorShape && vectorShapeToMove != null)
            {
                PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                float dx = mouseDoc.X - vectorMoveStartMouseDoc.X;
                float dy = mouseDoc.Y - vectorMoveStartMouseDoc.Y;

                RectangleF initialBounds = GetVectorShapeBounds(vectorMoveInitialPoints);
                if (snapToGridEnabled && !initialBounds.IsEmpty)
                {
                    float snappedLeft = SnapValueToGrid(initialBounds.Left + dx, SnapGridStep);
                    float snappedTop = SnapValueToGrid(initialBounds.Top + dy, SnapGridStep);
                    dx = snappedLeft - initialBounds.Left;
                    dy = snappedTop - initialBounds.Top;
                }

                var pageSize = GetPageSizeWithOffset(vectorShapeToMove.PageNumber);
                if (pageSize.Width > 0f && pageSize.Height > 0f && !initialBounds.IsEmpty)
                {
                    float minDx = -initialBounds.Left;
                    float maxDx = pageSize.Width - initialBounds.Right;
                    float minDy = -initialBounds.Top;
                    float maxDy = pageSize.Height - initialBounds.Bottom;
                    dx = Math.Max(minDx, Math.Min(maxDx, dx));
                    dy = Math.Max(minDy, Math.Min(maxDy, dy));
                }

                vectorShapeToMove.Points = vectorMoveInitialPoints
                    .Select(point => new PointF(point.X + dx, point.Y + dy))
                    .ToList();
                vectorShapeToMove.UpdatedAtUtc = DateTime.UtcNow;
                vectorInteractionChanged = vectorInteractionChanged || Math.Abs(dx) > 0.001f || Math.Abs(dy) > 0.001f;
                this.Cursor = Cursors.SizeAll;
                pdfViewer.Invalidate();
                return;
            }

            if (Control.MouseButtons == MouseButtons.None)
            {
                if (!TryUpdateVectorHoverCursor(e.Location) &&
                    !TryUpdateArrowHoverCursor(e.Location) &&
                    !TryUpdateRasterHoverCursor(e.Location))
                {
                    this.Cursor = Cursors.Default;
                }
            }

            if (isDrawing)
            {
                float x = Math.Min(startPoint.X, e.X);
                float y;
                float width = Math.Abs(e.X - startPoint.X);
                float height;
                if (markerRadioButton.Checked)
                {
                    bool markerCtrlBoxMode = (Control.ModifierKeys & Keys.Control) == Keys.Control;
                    isMarkerCtrlBoxMode = markerCtrlBoxMode;
                    if (markerCtrlBoxMode)
                    {
                        y = Math.Min(startPoint.Y, e.Y);
                        height = Math.Abs(e.Y - startPoint.Y);
                    }
                    else
                    {
                        if (IsMarkerVerticalForCurrentPage())
                        {
                            x = startPoint.X - (markerWidth * scaleFactor / 2f);
                            width = markerWidth * scaleFactor;
                            y = Math.Min(startPoint.Y, e.Y);
                            height = Math.Abs(e.Y - startPoint.Y);
                        }
                        else
                        {
                            y = (startPoint.Y - (markerWidth * scaleFactor / 2));
                            height = (markerWidth * scaleFactor);
                        }
                    }
                }
                else
                {
                    isMarkerCtrlBoxMode = false;
                    y = Math.Min(startPoint.Y, e.Y);
                    height = Math.Abs(e.Y - startPoint.Y);
                }
                currentSelection = new System.Drawing.RectangleF(x, y, width, height);
                pdfViewer.Invalidate();
            } else if (isMoving && !isClickOnIcon)
            {
                if (annotationToMove != null && !annotationToMove.AnnotationIsLocked)
                {
                    // Get current annotation Bounds (in "scaled" units, i.e. independent of zoom)
                    RectangleF bounds = annotationToMove.AnnotationBounds;

                    // Calculate new position in units before scaling (e.g. PDF points)
                    PointF mouseDoc = new PointF(e.X / scaleFactor, e.Y / scaleFactor);
                    float newX = mouseDoc.X - textMoveMouseOffset.X;
                    float newY = mouseDoc.Y - textMoveMouseOffset.Y;
                    if (snapToGridEnabled)
                    {
                        newX = SnapValueToGrid(newX, SnapGridStep);
                        newY = SnapValueToGrid(newY, SnapGridStep);
                    }

                    // Pobierz DPI z pdfViewer
                    float dpiX, dpiY;
                    using (Graphics g = pdfViewer.CreateGraphics())
                    {
                        dpiX = g.DpiX;
                        dpiY = g.DpiY;
                    }

                    // Pobierz rozmiary obszaru pdfViewer (w pikselach)
                    float clientWidth = pdfViewer.ClientSize.Width;
                    float clientHeight = pdfViewer.ClientSize.Height;

                    // Limit so annotation doesn't go beyond left and right edge
                    if (newX < - (bounds.Width * 72f / dpiX / 2))
                    {
                        newX = -bounds.Width * 72f / dpiX / 2;
                    }
                    else if (newX > clientWidth / scaleFactor - bounds.Width * 72f / dpiX / 2)
                    {
                        newX = clientWidth / scaleFactor - bounds.Width * 72f / dpiX / 2;
                    }

                    if (newY < -bounds.Height * 72f / dpiX / 2)
                    {
                        newY = -bounds.Height * 72f / dpiX / 2;
                    }
                    else if (newY > clientHeight / scaleFactor - bounds.Height * 72f / dpiX / 2)
                    {
                        newY = clientHeight / scaleFactor - bounds.Height * 72f / dpiX / 2;
                    }

                    // Update annotation position
                    annotationToMove.AnnotationBounds = new RectangleF(newX, newY, bounds.Width, bounds.Height);
                    pdfViewer.Invalidate();
                }

            }
        }


        private void OnMouseUp(object sender, MouseEventArgs e)
        {
            if (pdf == null)
                return;

            if (e.Button == MouseButtons.Middle)
            {
                EndMiddleMousePan();
                return;
            }

            if (isVectorShapeCreationMode)
            {
                return;
            }

             
            //if ((string)filterComboBox.SelectedItem == allComboItem)
            //{
            

            PageItemStatus status = allPageStatuses[currentPage - 1];
            if (IsCurrentPageMarkedForDeletion() && (e.Button == MouseButtons.Left || e.Button == MouseButtons.Right))
            {
                isDrawing = false;
                isMoving = false;
                annotationToMove = null;
                textMoveMouseOffset = PointF.Empty;
                ResetRasterInteractionState();
                ResetArrowInteractionState();
                ResetVectorInteractionState();
                selectedVectorShape = null;
                ResetGroupMoveState();
                currentSelection = RectangleF.Empty;
                isClickOnIcon = false;
                clickedIconType = IconType.None;
                annotationForIcon = null;
                ClearRasterIconClickState();
                ClearArrowIconClickState();
                ClearVectorIconClickState();
                pdfViewer.Invalidate();
                return;
            }


            if (e.Button == MouseButtons.Left)
            {
                if (isMovingObjectGroup)
                {
                    bool changed = groupMoveChanged;
                    ResetGroupMoveState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (arrowMouseActionInProgress)
                {
                    bool changed = arrowInteractionChanged;
                    ResetArrowInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (rasterMouseActionInProgress)
                {
                    bool changed = isMovingRasterObject || isRotatingRasterObject || isResizingRasterObject;
                    ResetRasterInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (vectorMouseActionInProgress)
                {
                    bool changed = vectorInteractionChanged;
                    ResetVectorInteractionState();
                    this.Cursor = Cursors.Default;
                    if (changed)
                    {
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    }
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnRasterIcon && rasterObjectForIcon != null)
                {
                    switch (clickedRasterIconType)
                    {
                        case RasterIconType.Edit:
                            EditRasterObject(rasterObjectForIcon);
                            break;
                        case RasterIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                rasterObjectForIcon.IsLocked = !rasterObjectForIcon.IsLocked;
                                rasterObjectForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = rasterObjectForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case RasterIconType.Duplicate:
                            DuplicateRasterObject(rasterObjectForIcon);
                            break;
                        case RasterIconType.Order:
                            ShowRasterOrderMenu(rasterObjectForIcon);
                            break;
                        case RasterIconType.ResetSize:
                            ResetRasterObjectSize(rasterObjectForIcon);
                            break;
                        case RasterIconType.Delete:
                            DeleteRasterObjectWithConfirmation(rasterObjectForIcon);
                            break;
                    }

                    ClearRasterIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnArrowIcon && arrowObjectForIcon != null)
                {
                    switch (clickedArrowIconType)
                    {
                        case ArrowIconType.Edit:
                            EditArrowObject(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                arrowObjectForIcon.IsLocked = !arrowObjectForIcon.IsLocked;
                                arrowObjectForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = arrowObjectForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case ArrowIconType.Duplicate:
                            DuplicateArrowObject(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Order:
                            ShowArrowOrderMenu(arrowObjectForIcon);
                            break;
                        case ArrowIconType.Delete:
                            DeleteArrowObjectWithConfirmation(arrowObjectForIcon);
                            break;
                    }

                    ClearArrowIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                if (isClickOnVectorIcon && vectorShapeForIcon != null)
                {
                    switch (clickedVectorIconType)
                    {
                        case VectorIconType.Edit:
                            EditVectorShapeObject(vectorShapeForIcon);
                            break;
                        case VectorIconType.Lock:
                            if (EnsureCurrentPageEditable(true))
                            {
                                vectorShapeForIcon.IsLocked = !vectorShapeForIcon.IsLocked;
                                vectorShapeForIcon.UpdatedAtUtc = DateTime.UtcNow;
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                string msg = vectorShapeForIcon.IsLocked
                                    ? LocalizedText("Msg_TextAnnotation_Locked")
                                    : LocalizedText("Msg_TextAnnotation_Unlocked");
                                MessageBox.Show(
                                    this,
                                    string.Format(LocalizedText("Msg_TextPositionInfo"), msg),
                                    Resources.Title_Info,
                                    MessageBoxButtons.OK,
                                    MessageBoxIcon.Information);
                            }
                            break;
                        case VectorIconType.Duplicate:
                            DuplicateVectorShape(vectorShapeForIcon);
                            break;
                        case VectorIconType.Order:
                            ShowVectorOrderMenu(vectorShapeForIcon);
                            break;
                        case VectorIconType.Delete:
                            DeleteVectorShapeWithConfirmation(vectorShapeForIcon);
                            break;
                    }

                    ClearVectorIconClickState();
                    pdfViewer.Invalidate();
                    return;
                }

                // If user clicked in icon button area
                if (isClickOnIcon && annotationForIcon != null)
                {
                    // Call appropriate action depending on clicked button
                    if (clickedIconType == IconType.Edit)
                    {
                        // For example: call annotation edit method
                        AddEditAnnotation(annotationForIcon);
                    }
                    else if (clickedIconType == IconType.Lock)
                    {
                        string msg;
                        if (annotationForIcon.AnnotationIsLocked)
                        {
                            annotationForIcon.AnnotationIsLocked = false;
                            pdfViewer.Invalidate();
                            msg = LocalizedText("Msg_TextAnnotation_Unlocked");
                        }
                        else
                        {
                            annotationForIcon.AnnotationIsLocked = true;
                            msg = LocalizedText("Msg_TextAnnotation_Locked");
                        }
                        pdfViewer.Invalidate();
                        MessageBox.Show(this, string.Format(Resources.Msg_TextPositionInfo, msg), Resources.Title_Info, MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                    else if (clickedIconType == IconType.Delete)
                    {
                        DeleteTextObjectWithConfirmation(annotationForIcon);

                    }
                    else if (clickedIconType == IconType.Duplicate)
                    {
                        DuplicateAnnotation(annotationForIcon);
                    }
                    // Refresh view
                    pdfViewer.Invalidate();
                }
                else
                {
                    if (isMoving)
                    {
                        isMoving = false;
                        textMoveMouseOffset = PointF.Empty;
                        this.Cursor = Cursors.Default;
                        projectWasChangedAfterLastSave = true;
                        saveProjectButton.Enabled = true;
                        saveProjectMenuItem.Enabled = true;
                    }
                    else
                    {
                        System.Drawing.RectangleF rect = new System.Drawing.RectangleF((currentSelection.X / scaleFactor), (currentSelection.Y / scaleFactor), (currentSelection.Width / scaleFactor), (currentSelection.Height / scaleFactor));
                        if (markerRadioButton.Checked)
                        {
                            renderTimer.Stop();
                            bool markerVerticalMode = !isMarkerCtrlBoxMode && IsMarkerVerticalForCurrentPage();
                            bool enoughWidth = markerVerticalMode
                                ? currentSelection.Height > markerHeight * scaleFactor
                                : currentSelection.Width > markerWidth * scaleFactor;
                            bool enoughHeightForCtrlBox = !isMarkerCtrlBoxMode || currentSelection.Height > markerHeight * scaleFactor;
                            if (isDrawing && enoughWidth && enoughHeightForCtrlBox)
                            {
                                // Marker + CTRL temporarily switches to box behavior.
                                bool markerModeForBlock = !isMarkerCtrlBoxMode;
                                redactionBlocks.Add(CreateRedactionBlockWithAutomaticClassification(
                                    rect,
                                    currentPage,
                                    isMarkerSelection: markerModeForBlock));
                                
                                

                                status.HasSelections = true;

                                if ((string)filterComboBox.SelectedItem == allComboItem)
                                {
                                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                    pagesListView.Invalidate(currentItem.Bounds);
                                }
                                else
                                {
                                    // rebuild list according to filter
                                    ApplyFilter((string)filterComboBox.SelectedItem);
                                }

                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                UpdateSelectionNavigationButtons();
                                renderTimer.Stop();
                                renderTimer.Start();
                            }
                        }
                        else if (boxRadioButton.Checked)
                        {
                            renderTimer.Stop();
                            if (isDrawing && currentSelection.Width > markerWidth * scaleFactor && currentSelection.Height > markerHeight * scaleFactor)
                            {
                                redactionBlocks.Add(CreateRedactionBlockWithAutomaticClassification(rect, currentPage, isMarkerSelection: false));

                                
                                status.HasSelections = true;

                                if ((string)filterComboBox.SelectedItem == allComboItem)
                                {
                                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                                    pagesListView.Invalidate(currentItem.Bounds);
                                }
                                else
                                {
                                    // rebuild list according to filter
                                    ApplyFilter((string)filterComboBox.SelectedItem);
                                }

                                
                                projectWasChangedAfterLastSave = true;
                                saveProjectButton.Enabled = true;
                                saveProjectMenuItem.Enabled = true;
                                UpdateSelectionNavigationButtons();
                                renderTimer.Stop();
                                renderTimer.Start();
                            }
                        }
                    }
                }

            }
            else if (e.Button == MouseButtons.Right)
            {
                if (selectedArrowObject != null &&
                    selectedArrowObject.PageNumber == currentPage &&
                    (IsPointNearArrowLine(selectedArrowObject, startPoint) || TryGetArrowHandleAtPoint(selectedArrowObject, startPoint, out _)))
                {
                    EditArrowObject(selectedArrowObject);
                    pdfViewer.Invalidate();
                    return;
                }

                TryShowRedactionContextMenu(startPoint);
            }
            isDrawing = false;
            isMarkerCtrlBoxMode = false;
            currentSelection = System.Drawing.Rectangle.Empty;
            pdfViewer.Invalidate();


            // Reset icon click flag
            isClickOnIcon = false;
            clickedIconType = IconType.None;
            annotationForIcon = null;
            ClearRasterIconClickState();
            ClearArrowIconClickState();
            ClearVectorIconClickState();
            if (!isMovingArrowObject && !isAdjustingArrowHandle)
            {
                arrowMouseActionInProgress = false;
            }

        }

        private bool TryShowRedactionContextMenu(Point location)
        {
            if (pdf == null)
            {
                return false;
            }

            float docX = location.X / scaleFactor;
            float docY = location.Y / scaleFactor;
            var block = redactionBlocks
                .Where(b => b.PageNumber == currentPage && b.Bounds.Contains(docX, docY))
                .LastOrDefault();
            if (block == null)
            {
                return false;
            }

            var menu = new ContextMenuStrip();
            menu.Items.Add(GetDeleteSelectionContextMenuText(), null, (_, __) => RemoveRedactionBlock(block));
            menu.Items.Add(new ToolStripSeparator());

            bool hasDynamicScopes = exclusionScopesCatalog.Count > 0;
            bool hasDynamicBases = legalBasesCatalog.Count > 0;
            var scopeMenu = new ToolStripMenuItem(GetScopeContextMenuText());
            if (hasDynamicScopes)
            {
                var noScopeItem = new ToolStripMenuItem(GetScopeNoneContextMenuText())
                {
                    Checked = string.IsNullOrWhiteSpace(block.ScopeId)
                };
                noScopeItem.Click += (_, __) => SetRedactionBlockScope(block, null);
                scopeMenu.DropDownItems.Add(noScopeItem);
                scopeMenu.DropDownItems.Add(new ToolStripSeparator());

                foreach (var scope in exclusionScopesCatalog.OrderBy(s => s.FriendlyName, StringComparer.CurrentCultureIgnoreCase))
                {
                    string scopeId = scope.ScopeId;
                    var scopeItem = new ToolStripMenuItem(scope.FriendlyName)
                    {
                        Checked = string.Equals(block.ScopeId, scopeId, StringComparison.OrdinalIgnoreCase),
                        ToolTipText = string.IsNullOrWhiteSpace(scope.Description) ? scopeId : scope.Description
                    };
                    scopeItem.Click += (_, __) => SetRedactionBlockScope(block, scopeId);
                    scopeMenu.DropDownItems.Add(scopeItem);
                }
            }
            else
            {
                scopeMenu.DropDownItems.Add(new ToolStripMenuItem(GetCatalogUnavailableContextMenuText())
                {
                    Enabled = false
                });
            }

            menu.Items.Add(scopeMenu);
            menu.Items.Add(new ToolStripSeparator());

            var addBasisItem = new ToolStripMenuItem(GetLegalBasisAddContextMenuText());
            addBasisItem.Click += (_, __) => BeginInvoke(new Action(() => AddLegalBasisFromContextMenu(block)));
            menu.Items.Add(addBasisItem);
            menu.Items.Add(new ToolStripSeparator());

            if (hasDynamicBases)
            {
                var clearBasisItem = new ToolStripMenuItem(GetLegalBasisNoneContextMenuText())
                {
                    Checked = block.BasisIds == null || block.BasisIds.Count == 0
                };
                clearBasisItem.Click += (_, __) => ClearRedactionBlockBasis(block);
                menu.Items.Add(clearBasisItem);
                menu.Items.Add(new ToolStripSeparator());

                HashSet<string> selectedBasisIds = new HashSet<string>(
                    block.BasisIds ?? new List<string>(),
                    StringComparer.OrdinalIgnoreCase);

                var sortedBases = GetOrderedLegalBasesForIndexing();
                var basisNumberById = sortedBases
                    .Where(b => b != null && !string.IsNullOrWhiteSpace(b.Id))
                    .Select((basis, index) => new { BasisId = basis.Id.Trim(), Number = index + 1 })
                    .ToDictionary(item => item.BasisId, item => item.Number, StringComparer.OrdinalIgnoreCase);

                LegalBasisSource? previousSource = null;
                foreach (var legalBasis in sortedBases)
                {
                    if (previousSource.HasValue && previousSource.Value != legalBasis.SourceKind)
                    {
                        menu.Items.Add(new ToolStripSeparator());
                    }

                    previousSource = legalBasis.SourceKind;
                    string basisId = legalBasis.Id;
                    basisNumberById.TryGetValue((basisId ?? string.Empty).Trim(), out int basisNumber);
                    var basisItem = new ToolStripMenuItem(FormatLegalBasisMenuLabel(legalBasis, basisNumber))
                    {
                        Checked = selectedBasisIds.Contains(basisId),
                        ToolTipText = string.IsNullOrWhiteSpace(legalBasis.FullCitation)
                            ? legalBasis.Title
                            : legalBasis.FullCitation
                    };
                    basisItem.Click += (_, __) => ToggleRedactionBlockBasis(block, basisId);
                    menu.Items.Add(basisItem);
                }
            }
            else
            {
                menu.Items.Add(new ToolStripMenuItem(GetCatalogUnavailableContextMenuText())
                {
                    Enabled = false
                });
            }

            menu.Show(pdfViewer, location);
            return true;
        }

        private void SetRedactionBlockScope(RedactionBlock block, string scopeId)
        {
            if (block == null)
            {
                return;
            }

            string normalizedScopeId = string.IsNullOrWhiteSpace(scopeId) ? null : scopeId.Trim();
            var previousBasis = new HashSet<string>(block.BasisIds ?? new List<string>(), StringComparer.OrdinalIgnoreCase);
            bool changed = !string.Equals(block.ScopeId, normalizedScopeId, StringComparison.OrdinalIgnoreCase);
            bool hadLegacyFootnote = block.FootnoteNumber.HasValue;

            block.ScopeId = normalizedScopeId;
            block.MatchedTag = null;
            block.ClassificationSource = ClassificationSourceManual;
            block.FootnoteNumber = null;
            changed = changed || hadLegacyFootnote;

            if (string.IsNullOrWhiteSpace(normalizedScopeId))
            {
                block.BasisIds = new List<string>();
                changed = changed || previousBasis.Count > 0;
            }
            else if (exclusionScopesById.TryGetValue(normalizedScopeId, out ExclusionScopeDefinition scope))
            {
                block.BasisIds = (scope.DefaultBasisIds ?? new List<string>())
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Where(id => legalBasesById.Count == 0 || legalBasesById.ContainsKey(id))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var nextBasis = new HashSet<string>(block.BasisIds, StringComparer.OrdinalIgnoreCase);
                changed = changed || !previousBasis.SetEquals(nextBasis);
            }

            if (!changed)
            {
                return;
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void ToggleRedactionBlockBasis(RedactionBlock block, string basisId)
        {
            if (block == null || string.IsNullOrWhiteSpace(basisId))
            {
                return;
            }

            string normalizedBasisId = basisId.Trim();
            if (block.BasisIds == null)
            {
                block.BasisIds = new List<string>();
            }

            bool changed;
            int existingIndex = block.BasisIds.FindIndex(id => string.Equals(id, normalizedBasisId, StringComparison.OrdinalIgnoreCase));
            if (existingIndex >= 0)
            {
                block.BasisIds.RemoveAt(existingIndex);
                changed = true;
            }
            else
            {
                block.BasisIds.Add(normalizedBasisId);
                changed = true;
            }

            if (!changed)
            {
                return;
            }

            block.ClassificationSource = ClassificationSourceManual;
            block.MatchedTag = null;
            block.FootnoteNumber = null;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private void ClearRedactionBlockBasis(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            if (block.BasisIds == null || block.BasisIds.Count == 0)
            {
                return;
            }

            block.BasisIds.Clear();
            block.ClassificationSource = ClassificationSourceManual;
            block.MatchedTag = null;
            block.FootnoteNumber = null;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private string FormatLegalBasisMenuLabel(LegalBasisDefinition legalBasis, int basisNumber = 0)
        {
            if (legalBasis == null)
            {
                return string.Empty;
            }

            string numberPrefix = basisNumber > 0 ? $"[{basisNumber}] " : string.Empty;
            return $"{numberPrefix}{legalBasis.Title}";
        }

        private List<LegalBasisDefinition> GetOrderedLegalBasesForIndexing()
        {
            return legalBasesCatalog
                .Where(b => b != null)
                .OrderBy(b => b.SourceKind == LegalBasisSource.Global ? 0 : 1)
                .ThenBy(b => b.Title, StringComparer.CurrentCultureIgnoreCase)
                .ThenBy(b => b.Id, StringComparer.CurrentCultureIgnoreCase)
                .ToList();
        }

