        private static string NormalizeClassificationSource(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return ClassificationSourceNone;
            }

            string normalized = value.Trim().ToLowerInvariant();
            if (normalized == ClassificationSourceAuto || normalized == ClassificationSourceManual)
            {
                return normalized;
            }

            return ClassificationSourceNone;
        }

        private static void NormalizeRedactionBlockMetadata(RedactionBlock block)
        {
            if (block == null)
            {
                return;
            }

            block.ScopeId = string.IsNullOrWhiteSpace(block.ScopeId) ? null : block.ScopeId.Trim();
            block.MatchedTag = string.IsNullOrWhiteSpace(block.MatchedTag) ? null : block.MatchedTag.Trim();
            block.InterestSubject = string.IsNullOrWhiteSpace(block.InterestSubject) ? null : block.InterestSubject.Trim();
            block.ClassificationSource = NormalizeClassificationSource(block.ClassificationSource);

            if (block.BasisIds == null)
            {
                block.BasisIds = new List<string>();
                return;
            }

            block.BasisIds = block.BasisIds
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private bool RemoveInvalidLegalBasisReferencesFromRedactions()
        {
            if (redactionBlocks == null || redactionBlocks.Count == 0)
            {
                return false;
            }

            var validBasisIds = new HashSet<string>(
                legalBasesById.Keys.Where(id => !string.IsNullOrWhiteSpace(id)),
                StringComparer.OrdinalIgnoreCase);

            bool changed = false;
            foreach (var block in redactionBlocks)
            {
                if (block == null)
                {
                    continue;
                }

                NormalizeRedactionBlockMetadata(block);
                if (block.BasisIds == null || block.BasisIds.Count == 0)
                {
                    continue;
                }

                List<string> filteredBasisIds = block.BasisIds
                    .Where(id => !string.IsNullOrWhiteSpace(id))
                    .Select(id => id.Trim())
                    .Where(id => validBasisIds.Contains(id))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                if (filteredBasisIds.Count == block.BasisIds.Count)
                {
                    continue;
                }

                block.BasisIds = filteredBasisIds;
                block.FootnoteNumber = null;
                changed = true;
            }

            return changed;
        }

        private RedactionBlock CreateRedactionBlockWithAutomaticClassification(RectangleF bounds, int pageNumber, bool isMarkerSelection = false)
        {
            var block = new RedactionBlock(bounds, pageNumber);
            block.IsMarkerSelection = isMarkerSelection;
            NormalizeRedactionBlockMetadata(block);
            TryApplyAutomaticFootnoteClassification(block);
            return block;
        }

        private bool TryApplyAutomaticFootnoteClassification(RedactionBlock block)
        {
            if (block == null || !autoFootnotesEnabled)
            {
                return false;
            }

            if (NormalizeClassificationSource(block.ClassificationSource) == ClassificationSourceManual)
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(inputPdfPath) || !File.Exists(inputPdfPath))
            {
                return false;
            }

            string extractedText;
            try
            {
                extractedText = ExtractTextFromRectangle(inputPdfPath, block);
            }
            catch (Exception ex)
            {
                LogDebug("Auto footnote classification text extraction failed: " + ex.Message);
                return false;
            }

            if (string.IsNullOrWhiteSpace(extractedText))
            {
                return false;
            }

            var detectedTags = PdfTextSearcher.DetectIdentifierTags(extractedText);
            if (detectedTags == null || detectedTags.Count == 0)
            {
                return false;
            }

            ExclusionScopeDefinition matchedScope = ResolveScopeForDetectedTags(detectedTags, out string matchedTag);
            if (matchedScope == null)
            {
                return false;
            }

            List<string> basisIds = (matchedScope.DefaultBasisIds ?? new List<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Where(id => legalBasesById.Count == 0 || legalBasesById.ContainsKey(id))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            block.ScopeId = matchedScope.ScopeId;
            block.BasisIds = basisIds;
            block.MatchedTag = matchedTag;
            block.ClassificationSource = ClassificationSourceAuto;

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"AutoClassify page={block.PageNumber} scope={block.ScopeId} tag={block.MatchedTag} " +
                    $"basis={string.Join(",", block.BasisIds ?? new List<string>())} text='{TruncateForLog(extractedText, 80)}'");
            }

            return true;
        }

        private ExclusionScopeDefinition ResolveScopeForDetectedTags(
            IReadOnlyList<string> detectedTags,
            out string matchedTag)
        {
            matchedTag = null;
            if (detectedTags == null || detectedTags.Count == 0 || exclusionScopesCatalog.Count == 0)
            {
                return null;
            }

            foreach (string rawTag in detectedTags)
            {
                if (string.IsNullOrWhiteSpace(rawTag))
                {
                    continue;
                }

                string tag = rawTag.Trim();
                ExclusionScopeDefinition scope = exclusionScopesCatalog.FirstOrDefault(s =>
                    s != null &&
                    s.AutoDetectTags != null &&
                    s.AutoDetectTags.Any(scopeTag => string.Equals(scopeTag, tag, StringComparison.OrdinalIgnoreCase)));

                if (scope != null)
                {
                    matchedTag = tag;
                    return scope;
                }
            }

            return null;
        }

        private static string TruncateForLog(string value, int maxLength)
        {
            if (string.IsNullOrEmpty(value) || maxLength <= 0 || value.Length <= maxLength)
            {
                return value ?? string.Empty;
            }

            return value.Substring(0, maxLength) + "...";
        }

        private static string GetFootnoteDetailText(int footnoteNumber)
        {
            return DemoFootnoteDetails.TryGetValue(footnoteNumber, out string detail) && !string.IsNullOrWhiteSpace(detail)
                ? detail
                : "Brak opisu podstawy prawnej.";
        }

        private RectangleF CalculateFootnoteBadgeRect(
            RectangleF selectionRect,
            float badgeWidth,
            float badgeHeight,
            int rotationOffset,
            float margin,
            bool clampToViewer,
            out float rotationCompensation)
        {
            rotationCompensation = 0f;
            float badgeX = selectionRect.Left - badgeWidth - margin;
            float badgeY = selectionRect.Top - badgeHeight - margin;

            if (clampToViewer)
            {
                if (badgeX < 0f)
                {
                    badgeX = Math.Min(
                        pdfViewer.ClientSize.Width - badgeWidth,
                        selectionRect.Left + margin);
                }
                if (badgeX + badgeWidth > pdfViewer.ClientSize.Width)
                {
                    badgeX = Math.Max(0f, pdfViewer.ClientSize.Width - badgeWidth);
                }
                if (badgeY < 0f)
                {
                    badgeY = Math.Min(
                        pdfViewer.ClientSize.Height - badgeHeight,
                        selectionRect.Top + margin);
                }
                if (badgeY + badgeHeight > pdfViewer.ClientSize.Height)
                {
                    badgeY = Math.Max(0f, pdfViewer.ClientSize.Height - badgeHeight);
                }
            }

            return new RectangleF(badgeX, badgeY, badgeWidth, badgeHeight);
        }

        private static PointF GetFootnoteAnchorPointForPdfExport(RectangleF selectionRect, int rotationOffset)
        {
            switch (NormalizeRotation(rotationOffset))
            {
                case 90:
                    return new PointF(selectionRect.Right, selectionRect.Bottom);
                case 180:
                    return new PointF(selectionRect.Left, selectionRect.Bottom);
                case 270:
                    return new PointF(selectionRect.Left, selectionRect.Top);
                case 0:
                default:
                    return new PointF(selectionRect.Right, selectionRect.Top);
            }
        }

        private static PointF ApplyFootnoteAnchorGapForPdfExport(PointF anchorPoint, int rotationOffset)
        {
            switch (NormalizeRotation(rotationOffset))
            {
                case 90:
                    return new PointF(anchorPoint.X, anchorPoint.Y + FootnoteMarkerGapPx);
                case 180:
                    return new PointF(anchorPoint.X - FootnoteMarkerGapPx, anchorPoint.Y);
                case 270:
                    return new PointF(anchorPoint.X, anchorPoint.Y - FootnoteMarkerGapPx);
                case 0:
                default:
                    return new PointF(anchorPoint.X + FootnoteMarkerGapPx, anchorPoint.Y);
            }
        }

        private void DrawCornerDebugMarkersOnPreview(Graphics graphics, RectangleF rect)
        {
            if (!DebugLogEnabled || graphics == null || rect.Width <= 0f || rect.Height <= 0f)
            {
                return;
            }

            using (var debugFont = new Font(this.Font.FontFamily, Math.Max(7f, this.Font.SizeInPoints - 1f), FontStyle.Bold))
            using (var debugBrush = new SolidBrush(System.Drawing.Color.Red))
            {
                PointF[] corners = new[]
                {
                    new PointF(rect.Left, rect.Top),
                    new PointF(rect.Right, rect.Top),
                    new PointF(rect.Right, rect.Bottom),
                    new PointF(rect.Left, rect.Bottom)
                };

                for (int i = 0; i < corners.Length; i++)
                {
                    graphics.DrawString((i + 1).ToString(CultureInfo.InvariantCulture), debugFont, debugBrush, corners[i].X + 1f, corners[i].Y + 1f);
                }
            }
        }

        private void DrawCornerDebugMarkersOnPdf(
            iText.Kernel.Pdf.Canvas.PdfCanvas pdfCanvas,
            PdfFont font,
            RectangleF selectionRect,
            int pageNumber,
            int rotation,
            bool includeBaseRotation)
        {
            if (!DebugLogEnabled || pdfCanvas == null || font == null || selectionRect.Width <= 0f || selectionRect.Height <= 0f)
            {
                return;
            }

            PointF[] corners = new[]
            {
                new PointF(selectionRect.Left, selectionRect.Top),
                new PointF(selectionRect.Right, selectionRect.Top),
                new PointF(selectionRect.Right, selectionRect.Bottom),
                new PointF(selectionRect.Left, selectionRect.Bottom)
            };

            pdfCanvas.SaveState();
            pdfCanvas.SetFillColor(new DeviceRgb(220, 0, 0));
            pdfCanvas.BeginText();
            pdfCanvas.SetFontAndSize(font, 7f);

            for (int i = 0; i < corners.Length; i++)
            {
                PointF cornerPdf = ConvertPointToPdfCoordinates(corners[i], pageNumber, rotation, includeBaseRotation);
                pdfCanvas.SetTextMatrix(1, 0, 0, 1, cornerPdf.X, cornerPdf.Y);
                pdfCanvas.ShowText((i + 1).ToString(CultureInfo.InvariantCulture));
            }

            pdfCanvas.EndText();
            pdfCanvas.RestoreState();
        }

        private void RenderVectorShapesToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            IEnumerable<VectorShapeObject> shapes)
        {
            if (pdfDoc == null || shapes == null)
            {
                return;
            }

            foreach (var vectorShape in shapes)
            {
                if (vectorShape == null || vectorShape.Points == null || vectorShape.Points.Count < 2)
                {
                    continue;
                }

                int pageNumber = vectorShape.PageNumber;
                if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                {
                    continue;
                }

                bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
                int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
                bool includeBaseRotation = !baseRotationBaked;
                var page = pdfDoc.GetPage(pageNumber);
                var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);

                VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
                VectorShapeStrokeKind strokeKind = ParseVectorStrokeKind(vectorShape.StrokeStyle);
                List<PointF> viewPoints = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points);
                List<PointF> pdfPoints = viewPoints
                    .Select(point => ConvertPointToPdfCoordinates(point, pageNumber, rotation, includeBaseRotation))
                    .ToList();
                if (pdfPoints.Count < 2)
                {
                    continue;
                }

                bool isClosed = IsShapeClosed(shapeType);
                bool supportsFill = ShapeTypeSupportsFill(shapeType);
                bool hasStroke = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
                float fillOpacity = supportsFill ? NormalizeVectorFillOpacity(vectorShape.FillOpacity) : 0f;
                bool hasFill = supportsFill && HasVisibleVectorColor(vectorShape.FillColorArgb) && fillOpacity > 0f;
                if (!hasStroke && !hasFill)
                {
                    continue;
                }

                pdfCanvas.SaveState();
                if (hasStroke)
                {
                    System.Drawing.Color strokeColor = System.Drawing.Color.FromArgb(vectorShape.StrokeColorArgb);
                    float strokeWidth = NormalizeVectorStrokeWidth(vectorShape.StrokeWidth);
                    pdfCanvas.SetStrokeColor(new DeviceRgb(strokeColor.R, strokeColor.G, strokeColor.B));
                    pdfCanvas.SetLineWidth(strokeWidth);
                    pdfCanvas.SetLineJoinStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineJoinStyle.ROUND);
                    pdfCanvas.SetLineCapStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineCapStyle.ROUND);
                    switch (strokeKind)
                    {
                        case VectorShapeStrokeKind.Dash:
                            pdfCanvas.SetLineDash(6f, 4f);
                            break;
                        case VectorShapeStrokeKind.Dot:
                            pdfCanvas.SetLineDash(1.5f, 3f);
                            break;
                        case VectorShapeStrokeKind.DashDot:
                            pdfCanvas.SetLineDash(new float[] { 6f, 3f, 1.5f, 3f }, 0f);
                            break;
                        case VectorShapeStrokeKind.DashDotDot:
                            pdfCanvas.SetLineDash(new float[] { 6f, 3f, 1.5f, 3f, 1.5f, 3f }, 0f);
                            break;
                    }
                }

                pdfCanvas.MoveTo(pdfPoints[0].X, pdfPoints[0].Y);
                for (int i = 1; i < pdfPoints.Count; i++)
                {
                    pdfCanvas.LineTo(pdfPoints[i].X, pdfPoints[i].Y);
                }

                if (isClosed && pdfPoints.Count >= 3)
                {
                    if (hasFill && hasStroke)
                    {
                        System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                        pdfCanvas.SetFillColor(new DeviceRgb(fillColor.R, fillColor.G, fillColor.B));
                        var fillState = new PdfExtGState().SetFillOpacity(fillOpacity);
                        pdfCanvas.SetExtGState(fillState);
                        pdfCanvas.ClosePathFillStroke();
                    }
                    else if (hasFill)
                    {
                        System.Drawing.Color fillColor = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                        pdfCanvas.SetFillColor(new DeviceRgb(fillColor.R, fillColor.G, fillColor.B));
                        var fillState = new PdfExtGState().SetFillOpacity(fillOpacity);
                        pdfCanvas.SetExtGState(fillState);
                        pdfCanvas.Fill();
                    }
                    else if (hasStroke)
                    {
                        pdfCanvas.ClosePathStroke();
                    }
                }
                else if (hasStroke)
                {
                    pdfCanvas.Stroke();
                }

                pdfCanvas.RestoreState();
            }
        }

        private void RenderRasterObjectToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            RasterObject rasterObject)
        {
            if (pdfDoc == null || rasterObject == null)
            {
                return;
            }

            int pageNumber = rasterObject.PageNumber;
            if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
            {
                return;
            }

            if (!TryCreateRasterImageData(rasterObject, out iText.IO.Image.ImageData imageData))
            {
                return;
            }

            bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
            int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
            var page = pdfDoc.GetPage(pageNumber);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            RectangleF viewBounds = rasterObject.Bounds;
            if (viewBounds.Width <= 0f || viewBounds.Height <= 0f)
            {
                return;
            }

            PointF centerView = new PointF(
                viewBounds.X + (viewBounds.Width / 2f),
                viewBounds.Y + (viewBounds.Height / 2f));
            PointF halfWidthVector = RotateVector(new PointF(viewBounds.Width / 2f, 0f), NormalizeRotation(rasterObject.Rotation));
            PointF halfHeightVector = RotateVector(new PointF(0f, viewBounds.Height / 2f), NormalizeRotation(rasterObject.Rotation));

            PointF topLeftView = new PointF(
                centerView.X - halfWidthVector.X - halfHeightVector.X,
                centerView.Y - halfWidthVector.Y - halfHeightVector.Y);
            PointF topRightView = new PointF(
                centerView.X + halfWidthVector.X - halfHeightVector.X,
                centerView.Y + halfWidthVector.Y - halfHeightVector.Y);
            PointF bottomLeftView = new PointF(
                centerView.X - halfWidthVector.X + halfHeightVector.X,
                centerView.Y - halfWidthVector.Y + halfHeightVector.Y);
            PointF bottomRightView = new PointF(
                centerView.X + halfWidthVector.X + halfHeightVector.X,
                centerView.Y + halfWidthVector.Y + halfHeightVector.Y);

            PointF topLeftPdf = ConvertPointToPdfCoordinates(topLeftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF topRightPdf = ConvertPointToPdfCoordinates(topRightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF bottomLeftPdf = ConvertPointToPdfCoordinates(bottomLeftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF bottomRightPdf = ConvertPointToPdfCoordinates(bottomRightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

            float a = bottomRightPdf.X - bottomLeftPdf.X;
            float b = bottomRightPdf.Y - bottomLeftPdf.Y;
            float c = topLeftPdf.X - bottomLeftPdf.X;
            float d = topLeftPdf.Y - bottomLeftPdf.Y;
            float e = bottomLeftPdf.X;
            float f = bottomLeftPdf.Y;

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"RasterExport page={pageNumber} bounds={viewBounds} rotObj={NormalizeRotation(rasterObject.Rotation)} pageRot={rotation} " +
                    $"tl={topLeftPdf.X:0.###},{topLeftPdf.Y:0.###} tr={topRightPdf.X:0.###},{topRightPdf.Y:0.###} bl={bottomLeftPdf.X:0.###},{bottomLeftPdf.Y:0.###} br={bottomRightPdf.X:0.###},{bottomRightPdf.Y:0.###} " +
                    $"matrix=[{a:0.#####} {b:0.#####} {c:0.#####} {d:0.#####} {e:0.###} {f:0.###}]");
            }

            float opacity = NormalizeOpacity(rasterObject.Opacity);
            if (opacity >= 0.999f)
            {
                pdfCanvas.AddImageWithTransformationMatrix(imageData, a, b, c, d, e, f, false);
            }
            else
            {
                var extGState = new PdfExtGState()
                    .SetFillOpacity(opacity)
                    .SetStrokeOpacity(opacity);
                pdfCanvas.SaveState();
                pdfCanvas.SetExtGState(extGState);
                pdfCanvas.AddImageWithTransformationMatrix(imageData, a, b, c, d, e, f, false);
                pdfCanvas.RestoreState();
            }
        }

        private void RenderArrowObjectToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            ArrowObject arrowObject)
        {
            if (pdfDoc == null || arrowObject == null)
            {
                return;
            }

            int pageNumber = arrowObject.PageNumber;
            if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
            {
                return;
            }

            bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
            int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
            var page = pdfDoc.GetPage(pageNumber);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            PointF startView = arrowObject.Start;
            PointF endView = arrowObject.End;
            PointF startPdf = ConvertPointToPdfCoordinates(startView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
            PointF endPdf = ConvertPointToPdfCoordinates(endView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

            float thickness = NormalizeArrowThickness(arrowObject.Thickness);
            float headLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
            float headWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
            System.Drawing.Color lineColor = GetArrowColor(arrowObject);
            var deviceColor = new DeviceRgb(lineColor.R, lineColor.G, lineColor.B);

            pdfCanvas.SaveState();
            pdfCanvas.SetLineWidth(thickness);
            pdfCanvas.SetLineCapStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineCapStyle.ROUND);
            pdfCanvas.SetLineJoinStyle(iText.Kernel.Pdf.Canvas.PdfCanvasConstants.LineJoinStyle.ROUND);
            pdfCanvas.SetStrokeColor(deviceColor);
            pdfCanvas.SetFillColor(deviceColor);

            if (TryBuildArrowHead(startView, endView, headLength, headWidth, out PointF leftView, out PointF rightView, out PointF lineEndView))
            {
                PointF lineEndPdf = ConvertPointToPdfCoordinates(lineEndView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
                PointF leftPdf = ConvertPointToPdfCoordinates(leftView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);
                PointF rightPdf = ConvertPointToPdfCoordinates(rightView, pageNumber, rotation, includeBaseRotation: !baseRotationBaked);

                pdfCanvas.MoveTo(startPdf.X, startPdf.Y);
                pdfCanvas.LineTo(lineEndPdf.X, lineEndPdf.Y);
                pdfCanvas.Stroke();

                pdfCanvas.MoveTo(endPdf.X, endPdf.Y);
                pdfCanvas.LineTo(leftPdf.X, leftPdf.Y);
                pdfCanvas.LineTo(rightPdf.X, rightPdf.Y);
                pdfCanvas.Fill();
            }
            else
            {
                pdfCanvas.MoveTo(startPdf.X, startPdf.Y);
                pdfCanvas.LineTo(endPdf.X, endPdf.Y);
                pdfCanvas.Stroke();
            }

            pdfCanvas.RestoreState();
        }

        private Dictionary<string, int> BuildLegalBasisFootnoteNumberMap(IEnumerable<RedactionBlock> blocks = null)
        {
            var map = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
            IEnumerable<RedactionBlock> sourceBlocks = blocks ?? redactionBlocks;
            if (sourceBlocks == null)
            {
                return map;
            }

            List<string> usedBasisIds = sourceBlocks
                .Where(block => block != null && block.BasisIds != null)
                .SelectMany(block => block.BasisIds)
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Select(id => id.Trim())
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (usedBasisIds.Count == 0)
            {
                return map;
            }

            var usedBasisIdSet = new HashSet<string>(usedBasisIds, StringComparer.OrdinalIgnoreCase);
            var orderedAllBases = GetOrderedLegalBasesForIndexing();
            int nextNumber = 1;

            // Footnote numbering is independent from legal-basis ordering in UI/context menu.
            // We keep basis order stable (global+local ordering), but compress numbering to used items only: 1..N.
            foreach (var basis in orderedAllBases)
            {
                if (basis == null || string.IsNullOrWhiteSpace(basis.Id))
                {
                    continue;
                }

                string basisId = basis.Id.Trim();
                if (!usedBasisIdSet.Contains(basisId) || map.ContainsKey(basisId))
                {
                    continue;
                }

                map[basisId] = nextNumber++;
            }

            // Any unknown/custom IDs that are used in blocks but not present in current catalogs.
            foreach (string basisId in usedBasisIds.Where(id => !map.ContainsKey(id)))
            {
                map[basisId] = nextNumber++;
            }

            return map;
        }

        private bool TryBuildFootnoteMarkerText(RedactionBlock block, IDictionary<string, int> basisNumberMap, out string markerText)
        {
            markerText = null;
            if (block == null)
            {
                return false;
            }

            List<int> markerNumbers = new List<int>();

            if (block.BasisIds != null && basisNumberMap != null && basisNumberMap.Count > 0)
            {
                foreach (string basisId in block.BasisIds)
                {
                    if (string.IsNullOrWhiteSpace(basisId))
                    {
                        continue;
                    }

                    if (basisNumberMap.TryGetValue(basisId.Trim(), out int number) && !markerNumbers.Contains(number))
                    {
                        markerNumbers.Add(number);
                    }
                }
            }

            if (markerNumbers.Count == 0 && block.FootnoteNumber.HasValue && block.FootnoteNumber.Value > 0)
            {
                markerNumbers.Add(block.FootnoteNumber.Value);
            }

            if (markerNumbers.Count == 0)
            {
                return false;
            }

            markerNumbers.Sort();
            markerText = markerNumbers.Count == 1
                ? $"[{markerNumbers[0]}]"
                : "[" + string.Join(",", markerNumbers) + "]";
            return true;
        }

        private List<(int Number, string Text)> BuildFootnoteSummaryEntries(
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap)
        {
            var entries = new List<(int Number, string Text)>();

            if (basisNumberMap != null && basisNumberMap.Count > 0)
            {
                foreach (var pair in basisNumberMap.OrderBy(p => p.Value))
                {
                    string text;
                    if (legalBasesById.TryGetValue(pair.Key, out LegalBasisDefinition legalBasis))
                    {
                        text = !string.IsNullOrWhiteSpace(legalBasis.FullCitation)
                            ? legalBasis.FullCitation
                            : legalBasis.Title;
                    }
                    else
                    {
                        text = pair.Key;
                    }

                    entries.Add((pair.Value, text));
                }

                return entries;
            }

            List<int> usedNumbers = (blocksWithFootnotes ?? new List<RedactionBlock>())
                .Where(block => block != null && block.FootnoteNumber.HasValue && block.FootnoteNumber.Value > 0)
                .Select(block => block.FootnoteNumber.Value)
                .Distinct()
                .OrderBy(number => number)
                .ToList();

            foreach (int number in usedNumbers)
            {
                entries.Add((number, GetFootnoteDetailText(number)));
            }

            return entries;
        }

        private string ResolveExclusionAuthorityForSummary(IList<RedactionBlock> blocksWithFootnotes)
        {
            if (!string.IsNullOrWhiteSpace(exclusionAuthorityName))
            {
                return exclusionAuthorityName.Trim();
            }

            foreach (var block in blocksWithFootnotes ?? new List<RedactionBlock>())
            {
                if (!string.IsNullOrWhiteSpace(block?.InterestSubject))
                {
                    return block.InterestSubject.Trim();
                }
            }

            return string.Empty;
        }

        private void RenderFootnoteMarkersToPdf(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            ISet<int> pagesWithBakedRotation,
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap,
            IDictionary<RedactionBlock, RectangleF> redactionVisualPdfBoundsByBlock)
        {
            if (pdfDoc == null || blocksWithFootnotes == null || blocksWithFootnotes.Count == 0)
            {
                return;
            }

            PdfFont markerFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA, "Cp1250");
            const float markerFontSize = 6f;

            foreach (var block in blocksWithFootnotes)
            {
                if (!TryBuildFootnoteMarkerText(block, basisNumberMap, out string markerText))
                {
                    continue;
                }

                int pageNumber = block.PageNumber;
                if (pageNumber < 1 || pageNumber > pdfDoc.GetNumberOfPages())
                {
                    continue;
                }

                bool baseRotationBaked = pagesWithBakedRotation != null && pagesWithBakedRotation.Contains(pageNumber);
                int rotation = baseRotationBaked ? GetRotationOffset(pageNumber) : GetEffectiveRotationDegrees(pageNumber);
                bool includeBaseRotation = !baseRotationBaked;
                iText.Kernel.Pdf.PdfPage page = pdfDoc.GetPage(pageNumber);
                RectangleF markerAnchorRect = GetFootnoteMarkerAnchorRect(
                    block,
                    page,
                    pageNumber,
                    rotation,
                    includeBaseRotation,
                    redactionVisualPdfBoundsByBlock);
                float markerWidth = Math.Max(8f, markerFont.GetWidth(markerText, markerFontSize));
                float markerHeight = markerFontSize + 1f;
                PointF markerViewPoint = GetFootnoteAnchorPointForPdfExport(markerAnchorRect, rotation);
                markerViewPoint = ApplyFootnoteAnchorGapForPdfExport(markerViewPoint, rotation);
                RectangleF badgeRect = new RectangleF(
                    markerViewPoint.X,
                    markerViewPoint.Y,
                    markerWidth,
                    markerHeight);

                PointF markerPdfPoint = ConvertPointToPdfCoordinates(
                    markerViewPoint,
                    pageNumber,
                    rotation,
                    includeBaseRotation: includeBaseRotation);

                if (DebugLogEnabled)
                {
                    LogDebug(
                        $"FootnoteExport page={pageNumber} footnote={markerText} rot={NormalizeRotation(rotation)} " +
                        $"selection={FormatRectFInvariant(markerAnchorRect)} badge={FormatRectFInvariant(badgeRect)} " +
                        $"viewPoint={FormatPointFInvariant(markerViewPoint)} pdfPoint={FormatPointFInvariant(markerPdfPoint)} " +
                        $"textW={markerWidth.ToString("0.###", CultureInfo.InvariantCulture)} " +
                        $"textH={markerHeight.ToString("0.###", CultureInfo.InvariantCulture)} " +
                        $"anchorUsed={FormatPointFInvariant(markerViewPoint)} " +
                        $"anchorTL={FormatPointFInvariant(new PointF(markerAnchorRect.Left, markerAnchorRect.Top))} " +
                        $"anchorTR={FormatPointFInvariant(new PointF(markerAnchorRect.Right, markerAnchorRect.Top))} " +
                        $"comp=0");
                }

                using (var layoutCanvas = new Canvas(new iText.Kernel.Pdf.Canvas.PdfCanvas(page), page.GetPageSize()))
                {
                    var markerParagraph = new iText.Layout.Element.Paragraph(markerText)
                        .SetMargin(0)
                        .SetPadding(0)
                        .SetMultipliedLeading(1f)
                        .SetFont(markerFont)
                        .SetFontSize(markerFontSize)
                        .SetFontColor(new DeviceRgb(0, 0, 0));

                    layoutCanvas.ShowTextAligned(
                        markerParagraph,
                        markerPdfPoint.X,
                        markerPdfPoint.Y,
                        pageNumber,
                        iText.Layout.Properties.TextAlignment.LEFT,
                        iText.Layout.Properties.VerticalAlignment.TOP,
                        0f);
                }

                DrawCornerDebugMarkersOnPdf(
                    new iText.Kernel.Pdf.Canvas.PdfCanvas(page),
                    markerFont,
                    markerAnchorRect,
                    pageNumber,
                    rotation,
                    includeBaseRotation);
            }
        }

        private RectangleF GetFootnoteMarkerAnchorRect(
            RedactionBlock block,
            iText.Kernel.Pdf.PdfPage page,
            int pageNumber,
            int rotation,
            bool includeBaseRotation,
            IDictionary<RedactionBlock, RectangleF> redactionVisualPdfBoundsByBlock)
        {
            if (block == null || page == null)
            {
                return RectangleF.Empty;
            }

            RectangleF anchorRect = block.Bounds;

            RectangleF sourcePdfRect = ConvertToPdfCoordinates(
                block.Bounds,
                pageNumber,
                rotation,
                includeBaseRotation);
            RectangleF visualPdfRect = sourcePdfRect;
            RectangleF cachedVisualRect = sourcePdfRect;
            bool hasCachedVisualRect = redactionVisualPdfBoundsByBlock != null &&
                                       redactionVisualPdfBoundsByBlock.TryGetValue(block, out cachedVisualRect);
            if (hasCachedVisualRect)
            {
                visualPdfRect = cachedVisualRect;
            }

            anchorRect = ConvertPdfToViewCoordinates(
                visualPdfRect,
                pageNumber,
                rotation,
                includeBaseRotation);

            int normalizedRotation = NormalizeRotation(rotation);

            if (DebugLogEnabled)
            {
                LogDebug(
                    $"FootnoteAnchor page={pageNumber} rot={normalizedRotation} includeBase={includeBaseRotation} " +
                    $"blockView={FormatRectFInvariant(block.Bounds)} sourcePdf={FormatRectFInvariant(sourcePdfRect)} " +
                    $"visualPdf={FormatRectFInvariant(visualPdfRect)} fromCache={hasCachedVisualRect} marker={block.IsMarkerSelection} " +
                    $"anchorView={FormatRectFInvariant(anchorRect)}");
            }

            return anchorRect;
        }

        private void AppendFootnotesSummaryPageIfNeeded(
            iText.Kernel.Pdf.PdfDocument pdfDoc,
            IList<RedactionBlock> blocksWithFootnotes,
            IDictionary<string, int> basisNumberMap)
        {
            if (pdfDoc == null || blocksWithFootnotes == null || blocksWithFootnotes.Count == 0)
            {
                return;
            }

            List<(int Number, string Text)> summaryEntries = BuildFootnoteSummaryEntries(blocksWithFootnotes, basisNumberMap);
            if (summaryEntries.Count == 0)
            {
                return;
            }

            PdfFont titleFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA_BOLD, "Cp1250");
            PdfFont bodyFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA, "Cp1250");
            PdfFont italicFont = PdfFontFactory.CreateFont(iText.IO.Font.Constants.StandardFonts.HELVETICA_OBLIQUE, "Cp1250");

            iText.Kernel.Pdf.PdfPage page = pdfDoc.AddNewPage(iText.Kernel.Geom.PageSize.A4);
            var pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
            float left = 50f;
            float top = page.GetPageSize().GetTop() - 56f;
            float maxTextWidth = page.GetPageSize().GetWidth() - (left * 2f);
            const float titleFontSize = 15f;
            const float bodyFontSize = 11f;
            const float lineHeight = 16f;
            float currentY = top;

            pdfCanvas.BeginText();
            pdfCanvas.SetFontAndSize(titleFont, titleFontSize);
            pdfCanvas.MoveText(left, currentY);
            pdfCanvas.ShowText(FootnoteSummaryTitle);
            pdfCanvas.EndText();

            currentY -= lineHeight * 1.5f;

            bool requiresAuthorityLine = (blocksWithFootnotes ?? new List<RedactionBlock>())
                .Any(block => BlockRequiresInterestSubject(block));
            if (requiresAuthorityLine)
            {
                pdfCanvas.BeginText();
                pdfCanvas.SetFontAndSize(italicFont, bodyFontSize);
                pdfCanvas.MoveText(left, currentY);
                pdfCanvas.ShowText(GetExclusionAuthoritySummaryLine(ResolveExclusionAuthorityForSummary(blocksWithFootnotes)));
                pdfCanvas.EndText();

                currentY -= lineHeight * 2f;
            }
            else
            {
                currentY -= lineHeight;
            }

            foreach (var entry in summaryEntries)
            {
                string line = $"[{entry.Number}] {entry.Text}";
                var wrappedLines = WrapTextToWidth(bodyFont, line, bodyFontSize, maxTextWidth);
                if (wrappedLines.Count == 0)
                {
                    wrappedLines.Add(line);
                }

                foreach (string wrappedLine in wrappedLines)
                {
                    if (currentY < 50f)
                    {
                        page = pdfDoc.AddNewPage(iText.Kernel.Geom.PageSize.A4);
                        pdfCanvas = new iText.Kernel.Pdf.Canvas.PdfCanvas(page);
                        currentY = page.GetPageSize().GetTop() - 56f;
                    }

                    pdfCanvas.BeginText();
                    pdfCanvas.SetFontAndSize(bodyFont, bodyFontSize);
                    pdfCanvas.MoveText(left, currentY);
                    pdfCanvas.ShowText(wrappedLine);
                    pdfCanvas.EndText();
                    currentY -= lineHeight;
                }

                currentY -= 6f;
            }
        }

        private void RemoveRedactionBlock(RedactionBlock blockToRemove)
        {
            if (blockToRemove == null)
            {
                return;
            }

            renderTimer.Stop();
            if (!redactionBlocks.Remove(blockToRemove))
            {
                return;
            }

            PageItemStatus status = allPageStatuses[currentPage - 1];
            RedactionBlock blocksByPage = redactionBlocks.FirstOrDefault(block => block.PageNumber == currentPage);
            if (blocksByPage == null)
            {
                status.HasSelections = false;

                if ((string)filterComboBox.SelectedItem == allComboItem)
                {
                    ListViewItem currentItem = pagesListView.Items[currentPage - 1];
                    UpdateItemTag(currentItem, currentPage, status.HasSelections, status.HasSearchResults, status.MarkedForDeletion, status.HasObjects);
                    pagesListView.Invalidate(currentItem.Bounds);
                }
                else
                {
                    // Rebuild list according to active filter.
                    ApplyFilter((string)filterComboBox.SelectedItem);
                }
            }

            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            UpdateSelectionNavigationButtons();
            renderTimer.Stop();
            renderTimer.Start();
            pdfViewer.Invalidate();
        }

        private void LogFootnoteBadgeLayoutIfNeeded(string markerText, RedactionBlock block, RectangleF selectionRect, RectangleF badgeRect, int rotationOffset, float rotationCompensation)
        {
            if (!DebugLogEnabled || block == null || string.IsNullOrWhiteSpace(markerText))
            {
                return;
            }

            if (rotationOffset != 90 && rotationOffset != 270)
            {
                return;
            }

            float topDelta = badgeRect.Top - selectionRect.Top;
            string key = string.Format(
                CultureInfo.InvariantCulture,
                "{0}|{1}|{2}|{3}|{4}",
                block.PageNumber,
                markerText,
                rotationOffset,
                FormatRectFInvariant(selectionRect),
                FormatRectFInvariant(badgeRect));

            if (string.Equals(lastFootnoteBadgeLayoutLogKey, key, StringComparison.Ordinal))
            {
                return;
            }

            lastFootnoteBadgeLayoutLogKey = key;
            LogDebug(
                $"FootnoteBadge page={block.PageNumber} footnote={markerText} rot={rotationOffset} " +
                $"selection={FormatRectFInvariant(selectionRect)} badge={FormatRectFInvariant(badgeRect)} " +
                $"topDelta={topDelta.ToString("0.###", CultureInfo.InvariantCulture)} comp={rotationCompensation.ToString("0.###", CultureInfo.InvariantCulture)} scale={scaleFactor.ToString("0.###", CultureInfo.InvariantCulture)}");
        }

        private void DrawVectorShapeOnPreview(Graphics graphics, VectorShapeObject vectorShape)
        {
            if (graphics == null || vectorShape == null || vectorShape.PageNumber != currentPage || vectorShape.Points == null || vectorShape.Points.Count < 2)
            {
                return;
            }

            VectorShapeType shapeType = ParseVectorShapeType(vectorShape.ShapeType);
            VectorShapeStrokeKind strokeKind = ParseVectorStrokeKind(vectorShape.StrokeStyle);
            PointF[] points = BuildVectorShapeRenderPoints(shapeType, vectorShape.Points)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToArray();
            if (points.Length < 2)
            {
                return;
            }

            using (var pen = new Pen(System.Drawing.Color.FromArgb(vectorShape.StrokeColorArgb), NormalizeVectorStrokeWidth(vectorShape.StrokeWidth) * scaleFactor))
            {
                bool isSelectedVector = IsVectorShapeSelected(vectorShape);
                bool hasStrokeColor = HasVisibleVectorColor(vectorShape.StrokeColorArgb);
                bool drawStroke = hasStrokeColor || isSelectedVector;
                if (isSelectedVector)
                {
                    pen.Color = System.Drawing.Color.Red;
                    pen.Width = Math.Max(pen.Width, 2f);
                }
                pen.DashStyle = ToDrawingDashStyle(strokeKind);
                pen.LineJoin = LineJoin.Round;
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;

                bool isClosed = IsShapeClosed(shapeType);
                bool supportsFill = ShapeTypeSupportsFill(shapeType);
                if (isClosed && points.Length >= 3)
                {
                    bool hasFillColor = HasVisibleVectorColor(vectorShape.FillColorArgb);
                    if (supportsFill && hasFillColor)
                    {
                        int alpha = (int)(NormalizeVectorFillOpacity(vectorShape.FillOpacity) * 255f);
                        alpha = Math.Max(0, Math.Min(255, alpha));
                        if (alpha > 0)
                        {
                            System.Drawing.Color fillBase = System.Drawing.Color.FromArgb(vectorShape.FillColorArgb);
                            using (var fillBrush = new SolidBrush(System.Drawing.Color.FromArgb(alpha, fillBase.R, fillBase.G, fillBase.B)))
                            {
                                graphics.FillPolygon(fillBrush, points);
                            }
                        }
                    }
                    if (drawStroke)
                    {
                        graphics.DrawPolygon(pen, points);
                    }
                }
                else
                {
                    if (drawStroke)
                    {
                        graphics.DrawLines(pen, points);
                    }
                }
            }
        }

        private void DrawVectorShapeDraftOnPreview(Graphics graphics)
        {
            if (graphics == null || !isVectorShapeCreationMode || vectorShapeDraftPoints.Count == 0)
            {
                return;
            }

            var draftSourcePoints = vectorShapeDraftPoints.ToList();
            if (vectorShapeDraftHoverActive)
            {
                draftSourcePoints.Add(vectorShapeDraftHoverPoint);
            }

            var draftPoints = BuildVectorShapeRenderPoints(activeVectorShapeType, draftSourcePoints)
                .Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor))
                .ToList();
            if (draftPoints.Count < 2)
            {
                return;
            }

            using (var pen = new Pen(System.Drawing.Color.DarkOrange, Math.Max(1f, activeVectorShapeDefaults.StrokeWidth * scaleFactor)))
            {
                pen.DashStyle = DashStyle.Dash;
                pen.LineJoin = LineJoin.Round;
                pen.StartCap = LineCap.Round;
                pen.EndCap = LineCap.Round;

                if (IsShapeClosed(activeVectorShapeType) && draftPoints.Count >= 3)
                {
                    graphics.DrawPolygon(pen, draftPoints.ToArray());
                }
                else
                {
                    graphics.DrawLines(pen, draftPoints.ToArray());
                }
            }

            foreach (PointF point in vectorShapeDraftPoints.Select(p => new PointF(p.X * scaleFactor, p.Y * scaleFactor)))
            {
                float size = 6f;
                graphics.FillEllipse(Brushes.DarkOrange, point.X - (size / 2f), point.Y - (size / 2f), size, size);
            }
        }

        private void DrawRasterObjectOnPreview(Graphics graphics, RasterObject rasterObject, bool multiSelectionActive)
        {
            if (graphics == null || rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!TryCreateRasterPreviewImage(rasterObject, out DrawingImage previewImage))
            {
                return;
            }

            using (previewImage)
            {
                bool isSelectedRaster = IsRasterObjectSelected(rasterObject);
                bool showRasterTools = selectedRasterObject != null &&
                                       selectedRasterObject.Id == rasterObject.Id &&
                                       GetGroupSelectionCount() == 0;
                RectangleF scaledBounds = new RectangleF(
                    rasterObject.Bounds.X * scaleFactor,
                    rasterObject.Bounds.Y * scaleFactor,
                    rasterObject.Bounds.Width * scaleFactor,
                    rasterObject.Bounds.Height * scaleFactor);

                var state = graphics.Save();
                try
                {
                    graphics.TranslateTransform(
                        scaledBounds.X + (scaledBounds.Width / 2f),
                        scaledBounds.Y + (scaledBounds.Height / 2f));
                    graphics.RotateTransform(rasterObject.Rotation);
                    graphics.TranslateTransform(-(scaledBounds.Width / 2f), -(scaledBounds.Height / 2f));
                    float opacity = NormalizeOpacity(rasterObject.Opacity);
                    if (opacity >= 0.999f)
                    {
                        graphics.DrawImage(previewImage, new RectangleF(0f, 0f, scaledBounds.Width, scaledBounds.Height));
                    }
                    else
                    {
                        using (var imageAttributes = new ImageAttributes())
                        {
                            var colorMatrix = new ColorMatrix
                            {
                                Matrix33 = opacity
                            };
                            imageAttributes.SetColorMatrix(colorMatrix, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
                            var drawRect = new Rectangle(
                                0,
                                0,
                                Math.Max(1, (int)Math.Round(scaledBounds.Width)),
                                Math.Max(1, (int)Math.Round(scaledBounds.Height)));
                            graphics.DrawImage(
                                previewImage,
                                drawRect,
                                0,
                                0,
                                previewImage.Width,
                                previewImage.Height,
                                GraphicsUnit.Pixel,
                                imageAttributes);
                        }
                    }
                    System.Drawing.Color borderColor = (isSelectedRaster && !multiSelectionActive)
                        ? System.Drawing.Color.Red
                        : System.Drawing.Color.SteelBlue;
                    float borderWidth = (isSelectedRaster && !multiSelectionActive) ? 2f : 1f;
                    using (var borderPen = new Pen(borderColor, borderWidth))
                    {
                        graphics.DrawRectangle(borderPen, 0f, 0f, scaledBounds.Width, scaledBounds.Height);
                    }
                }
                finally
                {
                    graphics.Restore(state);
                }

                RectangleF frameBounds = GetRasterObjectScreenFrameBounds(rasterObject);
                if (frameBounds.Width > 0f && frameBounds.Height > 0f)
                {
                    using (var framePen = new Pen(System.Drawing.Color.Green, 1f))
                    {
                        graphics.DrawRectangle(framePen, frameBounds.X, frameBounds.Y, frameBounds.Width, frameBounds.Height);
                    }

                    if (multiSelectionActive && isSelectedRaster)
                    {
                        DrawGroupSelectionOutline(graphics, frameBounds);
                    }
                }

                if (showRasterTools && TryGetRasterRotationHandleRect(rasterObject, out RectangleF handleRect, out PointF connectorPoint))
                {
                    PointF handleCenter = new PointF(
                        handleRect.X + (handleRect.Width / 2f),
                        handleRect.Y + (handleRect.Height / 2f));
                    using (var connectorPen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                    {
                        graphics.DrawLine(connectorPen, connectorPoint, handleCenter);
                    }
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 2f))
                    {
                        graphics.FillEllipse(handleBrush, handleRect);
                        graphics.DrawEllipse(handlePen, handleRect);
                    }
                }

                if (showRasterTools && TryGetRasterResizeHandleRects(rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> resizeHandles))
                {
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 1.5f))
                    {
                        foreach (var kvp in resizeHandles)
                        {
                            if (kvp.Key == RasterResizeHandleType.None)
                            {
                                continue;
                            }

                            graphics.FillRectangle(handleBrush, kvp.Value);
                            graphics.DrawRectangle(handlePen, kvp.Value.X, kvp.Value.Y, kvp.Value.Width, kvp.Value.Height);
                        }
                    }
                }

                if (showRasterTools && TryGetRasterIconRects(rasterObject, out Dictionary<RasterIconType, Rectangle> iconRects))
                {
                    DrawIconButton(graphics, iconRects[RasterIconType.Edit], "\uE70F");
                    DrawIconButton(
                        graphics,
                        iconRects[RasterIconType.Lock],
                        rasterObject.IsLocked ? "\uE72E" : "\uE785");
                    DrawIconButton(graphics, iconRects[RasterIconType.Duplicate], "\uE8C8");
                    DrawIconButton(graphics, iconRects[RasterIconType.Order], "\u2630");
                    DrawIconButton(graphics, iconRects[RasterIconType.ResetSize], "\uE777");
                    DrawIconButton(graphics, iconRects[RasterIconType.Delete], "\uE74D");
                }
            }
        }

        private void DrawArrowObjectOnPreview(Graphics graphics, ArrowObject arrowObject, bool multiSelectionActive)
        {
            if (graphics == null || arrowObject == null || arrowObject.PageNumber != currentPage)
            {
                return;
            }

            arrowObject.Thickness = NormalizeArrowThickness(arrowObject.Thickness);
            arrowObject.HeadLength = NormalizeArrowHeadLength(arrowObject.HeadLength);
            arrowObject.HeadWidth = NormalizeArrowHeadWidth(arrowObject.HeadWidth);
            if (!IsArrowColorValid(arrowObject))
            {
                arrowObject.LineColorArgb = DefaultArrowColor.ToArgb();
            }

            bool isSelectedArrow = IsArrowObjectSelected(arrowObject);
            bool showArrowTools = selectedArrowObject != null &&
                                  selectedArrowObject.Id == arrowObject.Id &&
                                  GetGroupSelectionCount() == 0;
            System.Drawing.Color baseColor = (isSelectedArrow && !multiSelectionActive)
                ? System.Drawing.Color.Red
                : GetArrowColor(arrowObject);
            PointF startScreen = GetArrowScreenPoint(arrowObject.Start);
            PointF endScreen = GetArrowScreenPoint(arrowObject.End);
            float thicknessPx = Math.Max(1f, arrowObject.Thickness * scaleFactor);
            float headLengthPx = Math.Max(4f, arrowObject.HeadLength * scaleFactor);
            float headWidthPx = Math.Max(4f, arrowObject.HeadWidth * scaleFactor);

            var state = graphics.Save();
            try
            {
                graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
                if (TryBuildArrowHead(startScreen, endScreen, headLengthPx, headWidthPx, out PointF leftPoint, out PointF rightPoint, out PointF lineEndPoint))
                {
                    using (var pen = new Pen(baseColor, thicknessPx))
                    {
                        pen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        graphics.DrawLine(pen, startScreen, lineEndPoint);
                    }

                    using (var brush = new SolidBrush(baseColor))
                    {
                        graphics.FillPolygon(brush, new[] { endScreen, leftPoint, rightPoint });
                    }
                }
                else
                {
                    using (var pen = new Pen(baseColor, thicknessPx))
                    {
                        pen.StartCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.EndCap = System.Drawing.Drawing2D.LineCap.Round;
                        pen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        graphics.DrawLine(pen, startScreen, endScreen);
                    }
                }

                if (multiSelectionActive && isSelectedArrow)
                {
                    float minX = Math.Min(startScreen.X, endScreen.X);
                    float maxX = Math.Max(startScreen.X, endScreen.X);
                    float minY = Math.Min(startScreen.Y, endScreen.Y);
                    float maxY = Math.Max(startScreen.Y, endScreen.Y);
                    RectangleF arrowBounds = new RectangleF(minX, minY, Math.Max(1f, maxX - minX), Math.Max(1f, maxY - minY));
                    DrawGroupSelectionOutline(graphics, arrowBounds);
                }

                if (showArrowTools)
                {
                    RectangleF startHandle = new RectangleF(
                        startScreen.X - ArrowHandleRadius,
                        startScreen.Y - ArrowHandleRadius,
                        ArrowHandleRadius * 2f,
                        ArrowHandleRadius * 2f);
                    RectangleF endHandle = new RectangleF(
                        endScreen.X - ArrowHandleRadius,
                        endScreen.Y - ArrowHandleRadius,
                        ArrowHandleRadius * 2f,
                        ArrowHandleRadius * 2f);
                    using (var handleBrush = new SolidBrush(System.Drawing.Color.White))
                    using (var handlePen = new Pen(System.Drawing.Color.OrangeRed, 2f))
                    {
                        graphics.FillEllipse(handleBrush, startHandle);
                        graphics.DrawEllipse(handlePen, startHandle);
                        graphics.FillEllipse(handleBrush, endHandle);
                        graphics.DrawEllipse(handlePen, endHandle);
                    }

                    if (TryGetArrowIconRects(arrowObject, out Dictionary<ArrowIconType, Rectangle> arrowIconRects))
                    {
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Edit], "\uE70F");
                        DrawIconButton(
                            graphics,
                            arrowIconRects[ArrowIconType.Lock],
                            arrowObject.IsLocked ? "\uE72E" : "\uE785");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Duplicate], "\uE8C8");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Order], "\u2630");
                        DrawIconButton(graphics, arrowIconRects[ArrowIconType.Delete], "\uE74D");
                    }
                }
            }
            finally
            {
                graphics.Restore(state);
            }
        }

        private void DrawTextAnnotationOnPreview(Graphics graphics, TextAnnotation annotation, bool multiSelectionActive)
        {
            if (graphics == null || annotation == null || annotation.PageNumber != currentPage)
            {
                return;
            }

            System.Drawing.Rectangle rect = new System.Drawing.Rectangle(
                (int)(annotation.AnnotationBounds.X * scaleFactor),
                (int)(annotation.AnnotationBounds.Y * scaleFactor),
                (int)(annotation.AnnotationBounds.Width * scaleFactor * 72f / graphics.DpiX),
                (int)(annotation.AnnotationBounds.Height * scaleFactor * 72f / graphics.DpiY)
            );

            bool isSelectedAnnotation = IsTextAnnotationSelected(annotation);
            bool showTextTools = selectedTextAnnotation != null &&
                                 ReferenceEquals(selectedTextAnnotation, annotation) &&
                                 GetGroupSelectionCount() == 0;

            using (Pen pen = new Pen(System.Drawing.Color.Green, 1f))
            {
                graphics.DrawRectangle(pen, rect);
            }

            StringAlignment align;
            switch (annotation.AnnotationAlignment)
            {
                case System.Windows.Forms.HorizontalAlignment.Left:
                    align = StringAlignment.Near;
                    break;
                case System.Windows.Forms.HorizontalAlignment.Center:
                    align = StringAlignment.Center;
                    break;
                case System.Windows.Forms.HorizontalAlignment.Right:
                    align = StringAlignment.Far;
                    break;
                default:
                    align = StringAlignment.Near;
                    break;
            }

            StringFormat stringFormat = StringFormat.GenericTypographic;
            stringFormat.Alignment = align;
            stringFormat.LineAlignment = StringAlignment.Near;
            stringFormat.FormatFlags = StringFormatFlags.NoWrap;
            stringFormat.Trimming = StringTrimming.None;

            float dpiCorrection = 72f / graphics.DpiY;
            int annotationRotation = NormalizeRotation(annotation.AnnotationRotation);
            SizeF baseSize = GetAnnotationSize(annotation.AnnotationText, annotation.AnnotationFont, 0);
            float layoutWidth = baseSize.Width * scaleFactor * 72f / graphics.DpiX;
            float layoutHeight = baseSize.Height * scaleFactor * 72f / graphics.DpiY;

            using (SolidBrush brush = new SolidBrush((isSelectedAnnotation && !multiSelectionActive) ? System.Drawing.Color.Red : annotation.AnnotationColor))
            {
                float scaledFontSize = annotation.AnnotationFont.Size * scaleFactor * dpiCorrection;
                using (Font scaledFont = new Font(annotation.AnnotationFont.FontFamily, scaledFontSize, annotation.AnnotationFont.Style))
                {
                    float rotationRadians = (float)(annotationRotation * Math.PI / 180.0);
                    float rotCos = (float)Math.Cos(rotationRadians);
                    float rotSin = (float)Math.Sin(rotationRadians);
                    PointF rotationOffset = GetRotationOffsetForBounds(annotationRotation, layoutWidth, layoutHeight);
                    float offsetX = rotationOffset.X;
                    float offsetY = rotationOffset.Y;

                    RectangleF layoutRect = new RectangleF(0, 0, layoutWidth, layoutHeight);
                    var state = graphics.Save();
                    graphics.Transform = new System.Drawing.Drawing2D.Matrix(
                        rotCos, rotSin, -rotSin, rotCos,
                        rect.X + offsetX, rect.Y + offsetY);
                    graphics.DrawString(
                        annotation.AnnotationText,
                        scaledFont,
                        brush,
                        layoutRect,
                        stringFormat
                    );
                    graphics.Restore(state);
                }
            }

            if (multiSelectionActive && isSelectedAnnotation)
            {
                DrawGroupSelectionOutline(graphics, rect);
            }

            if (showTextTools && TryGetAnnotationIconRects(annotation, graphics.DpiX, graphics.DpiY, out Dictionary<IconType, Rectangle> annotationIconRects))
            {
                DrawIconButton(graphics, annotationIconRects[IconType.Edit], "\uE70F");
                DrawIconButton(
                    graphics,
                    annotationIconRects[IconType.Lock],
                    annotation.AnnotationIsLocked ? "\uE72E" : "\uE785");
                DrawIconButton(graphics, annotationIconRects[IconType.Duplicate], "\uE8C8");
                DrawIconButton(graphics, annotationIconRects[IconType.Delete], "\uE74D");
            }
        }

        private void OnPaint(object sender, PaintEventArgs e)
        {
            // Draw current selection
            if (isDrawing && currentSelection.Width > 0 && currentSelection.Height > 0)
            {
                using (SolidBrush brush = new SolidBrush(System.Drawing.Color.FromArgb(128, 255, 0, 0)))
                {
                    e.Graphics.FillRectangle(brush, currentSelection);
                }
            }

            Dictionary<string, int> previewBasisNumberMap = BuildLegalBasisFootnoteNumberMap();

            // Drawing saved redaction blocks for current page
            foreach (var block in redactionBlocks.Where(b => b.PageNumber == currentPage))
            {
                using (SolidBrush brush = new SolidBrush(System.Drawing.Color.FromArgb(128, 255, 0, 0)))
                {
                    System.Drawing.RectangleF rect = new System.Drawing.RectangleF((block.Bounds.X * scaleFactor), (block.Bounds.Y * scaleFactor), (block.Bounds.Width * scaleFactor), (block.Bounds.Height * scaleFactor));
                    e.Graphics.FillRectangle(brush, rect);
                    DrawCornerDebugMarkersOnPreview(e.Graphics, rect);

                    if (TryBuildFootnoteMarkerText(block, previewBasisNumberMap, out string badgeText))
                    {
                        string previewBadgeText = badgeText
                            .Replace("[", string.Empty)
                            .Replace("]", string.Empty)
                            .Replace(".", ",")
                            .Replace(",", ", ");
                        float badgeScale = Math.Max(1f, scaleFactor);
                        float badgeFontSize = Math.Max(9f, (this.Font.SizeInPoints * badgeScale) - 0.5f);
                        using (Font badgeFont = CreatePreviewBadgeFont(badgeFontSize))
                        {
                            TextRenderingHint previousTextRenderingHint = e.Graphics.TextRenderingHint;
                            try
                            {
                                e.Graphics.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;
                                SizeF textSize = e.Graphics.MeasureString(previewBadgeText, badgeFont);
                                float badgePaddingX = Math.Max(4f, 4f * badgeScale);
                                float badgePaddingY = Math.Max(1f, 1f * badgeScale);
                                float badgeWidth = textSize.Width + (badgePaddingX * 2f);
                                float badgeHeight = textSize.Height + (badgePaddingY * 2f);
                                float margin = Math.Max(2f, 2f * badgeScale);
                                int rotationOffset = NormalizeRotation(GetRotationOffset(block.PageNumber));
                                float halfDiff = (badgeWidth - badgeHeight) / 2f;

                                float badgeX;
                                float badgeY;
                                switch (rotationOffset)
                                {
                                    case 90:
                                        badgeX = rect.Right - badgeWidth;
                                        badgeY = rect.Bottom + margin;
                                        break;
                                    case 180:
                                        badgeX = rect.Left - badgeWidth - margin;
                                        badgeY = rect.Bottom - badgeHeight;
                                        break;
                                    case 270:
                                        badgeX = rect.Left;
                                        badgeY = rect.Top - badgeHeight - margin;
                                        break;
                                    default:
                                        badgeX = rect.Right + margin;
                                        badgeY = rect.Top;
                                        break;
                                }

                                if (rotationOffset == 90)
                                {
                                    badgeX += halfDiff;
                                    badgeY += halfDiff;
                                }
                                else if (rotationOffset == 270)
                                {
                                    badgeX -= halfDiff;
                                    badgeY -= halfDiff;
                                }

                            float badgeVerticalShift = badgeHeight / 2f;
                            switch (rotationOffset)
                            {
                                case 90:
                                    badgeX += badgeVerticalShift;
                                        break;
                                    case 180:
                                        badgeY += badgeVerticalShift;
                                        break;
                                    case 270:
                                        badgeX -= badgeVerticalShift;
                                        break;
                                    default:
                                    badgeY -= badgeVerticalShift;
                                    break;
                            }

                            float markerThicknessPx = markerWidth * scaleFactor;
                            float minSelectionDim = Math.Min(rect.Width, rect.Height);
                            float maxSelectionDim = Math.Max(rect.Width, rect.Height);
                            bool isThinElongatedSelection = markerThicknessPx > 0f &&
                                                            minSelectionDim <= markerThicknessPx * 1.4f &&
                                                            maxSelectionDim >= minSelectionDim * 3f;
                            if (isThinElongatedSelection)
                            {
                                bool markerAxisIsVertical = rect.Height > rect.Width;
                                float markerAxisCenterY = rect.Top + (rect.Height / 2f);
                                float markerAxisCenterX = rect.Left + (rect.Width / 2f);

                                if (!markerAxisIsVertical)
                                {
                                    if (rotationOffset == 0)
                                    {
                                        // Bottom edge of badge sits on marker symmetry axis.
                                        badgeY = markerAxisCenterY - badgeHeight;
                                    }
                                    else if (rotationOffset == 180)
                                    {
                                        // For 180 deg badge rotation, bottom edge maps to top edge in view space.
                                        badgeY = markerAxisCenterY;
                                    }
                                }
                                else
                                {
                                    if (rotationOffset == 90)
                                    {
                                        // For 90 deg badge rotation, bottom edge maps to left edge in view space.
                                        badgeX = markerAxisCenterX;
                                    }
                                    else if (rotationOffset == 270)
                                    {
                                        // For 270 deg badge rotation, bottom edge maps to right edge in view space.
                                        badgeX = markerAxisCenterX - badgeWidth;
                                    }
                                }
                            }

                            if (badgeX + badgeWidth > pdfViewer.ClientSize.Width)
                            {
                                badgeX = Math.Max(0f, rect.Right - badgeWidth - 2f);
                            }
                                if (badgeX < 0f)
                                {
                                    badgeX = 0f;
                                }
                                if (badgeY < 0f)
                                {
                                    badgeY = 0f;
                                }
                                if (badgeY + badgeHeight > pdfViewer.ClientSize.Height)
                                {
                                    badgeY = Math.Max(0f, pdfViewer.ClientSize.Height - badgeHeight);
                                }

                                RectangleF badgeRect = new RectangleF(badgeX, badgeY, badgeWidth, badgeHeight);
                                LogFootnoteBadgeLayoutIfNeeded(badgeText, block, rect, badgeRect, rotationOffset, halfDiff);
                                using (SolidBrush badgeBackground = new SolidBrush(System.Drawing.Color.FromArgb(64, 255, 0, 0)))
                                using (Pen badgeBorder = new Pen(System.Drawing.Color.FromArgb(220, 255, 0, 0), Math.Max(1f, badgeScale * 0.9f)))
                                using (SolidBrush badgeTextBrush = new SolidBrush(System.Drawing.Color.FromArgb(255, 255, 0, 0)))
                                {
                                    float borderInset = 3f;
                                    RectangleF borderRect = new RectangleF(
                                        badgeRect.X + borderInset,
                                        badgeRect.Y + borderInset,
                                        Math.Max(1f, badgeRect.Width - (borderInset * 2f)),
                                        Math.Max(1f, badgeRect.Height - (borderInset * 2f)));

                                    if (rotationOffset == 0)
                                    {
                                        e.Graphics.FillRectangle(badgeBackground, borderRect);
                                        e.Graphics.DrawRectangle(badgeBorder, borderRect.X, borderRect.Y, borderRect.Width, borderRect.Height);
                                        e.Graphics.DrawString(
                                            previewBadgeText,
                                            badgeFont,
                                            badgeTextBrush,
                                            badgeRect.X + badgePaddingX,
                                            badgeRect.Y + badgePaddingY);
                                    }
                                    else
                                    {
                                        var state = e.Graphics.Save();
                                        float centerX = badgeRect.X + (badgeRect.Width / 2f);
                                        float centerY = badgeRect.Y + (badgeRect.Height / 2f);
                                        e.Graphics.TranslateTransform(centerX, centerY);
                                        e.Graphics.RotateTransform(rotationOffset);
                                        e.Graphics.TranslateTransform(-centerX, -centerY);

                                        e.Graphics.FillRectangle(badgeBackground, borderRect);
                                        e.Graphics.DrawRectangle(badgeBorder, borderRect.X, borderRect.Y, borderRect.Width, borderRect.Height);
                                        e.Graphics.DrawString(
                                            previewBadgeText,
                                            badgeFont,
                                            badgeTextBrush,
                                            badgeRect.X + badgePaddingX,
                                            badgeRect.Y + badgePaddingY);

                                        e.Graphics.Restore(state);
                                    }
                                }
                            }
                            finally
                            {
                                e.Graphics.TextRenderingHint = previousTextRenderingHint;
                            }
                        }
                    }
                }
            }

            TextLocation selectedSearchLocation = null;
            if (currentLocationIndex >= 0 && currentLocationIndex < searchLocations.Count)
            {
                selectedSearchLocation = searchLocations[currentLocationIndex];
            }
            bool multiSelectionActive = GetTotalSelectedObjectsCount() > 1;

            // Drawing saved search results
            foreach (var location in searchLocations)
            {
                if (location.PageNumber == currentPage)
                {
                    float x = location.Rect.GetX();
                    float y = location.Rect.GetY();
                    float w = location.Rect.GetWidth();
                    float h = location.Rect.GetHeight();
                    int rotation = GetEffectiveRotationDegrees(location.PageNumber);

                    RectangleF rectF = new RectangleF(x, y, w, h);
                    var pdfCoordinates = ConvertPdfToViewCoordinates(rectF, currentPage, rotation);

                    // Default highlight – e.g. yellow
                    System.Drawing.Color highlightColor = System.Drawing.Color.FromArgb(128, 255, 215, 0);

                    // Scale rectangle
                    float sc_x = pdfCoordinates.X * scaleFactor;
                    float sc_y = pdfCoordinates.Y * scaleFactor;
                    float sc_w = pdfCoordinates.Width * scaleFactor;
                    float sc_h = pdfCoordinates.Height * scaleFactor;
                    float highlightPad = Math.Max(2f, Math.Min(sc_w, sc_h) * 0.35f);
                    RectangleF primaryHighlightRect = new RectangleF(
                        sc_x - highlightPad,
                        sc_y - highlightPad,
                        sc_w + (highlightPad * 2f),
                        sc_h + (highlightPad * 2f));

                    using (Pen pen = new Pen(highlightColor, 3))
                    {
                        e.Graphics.DrawRectangle(pen, primaryHighlightRect.X, primaryHighlightRect.Y, primaryHighlightRect.Width, primaryHighlightRect.Height);
                    }

                    bool isSelectedSearchLocation = ReferenceEquals(location, selectedSearchLocation);
                    if (isSelectedSearchLocation)
                    {
                        // If this is currently selected location, change color to gray
                        highlightColor = System.Drawing.Color.FromArgb(255, 128, 128, 128);
                        float selectedPad = highlightPad * 2f;
                        RectangleF selectedHighlightRect = new RectangleF(
                            sc_x - selectedPad,
                            sc_y - selectedPad,
                            sc_w + (selectedPad * 2f),
                            sc_h + (selectedPad * 2f));

                        using (Pen pen = new Pen(highlightColor, 3))
                        {
                            e.Graphics.DrawRectangle(pen, selectedHighlightRect.X, selectedHighlightRect.Y, selectedHighlightRect.Width, selectedHighlightRect.Height);
                        }

                        if (DebugLogEnabled && (rotation == 90 || rotation == 270))
                        {
                            RectangleF scaledRect = new RectangleF(sc_x, sc_y, sc_w, sc_h);
                            LogDebug(
                                $"SearchHighlight page={location.PageNumber} idx={currentLocationIndex} pageRot={rotation} lineRot={NormalizeRotation(location.PageRotation)} " +
                                $"pdfRect={FormatRectFInvariant(rectF)} viewRect={FormatRectFInvariant(pdfCoordinates)} scaledRect={FormatRectFInvariant(scaledRect)} " +
                                $"drawPrimary={FormatRectFInvariant(primaryHighlightRect)} drawSelected={FormatRectFInvariant(selectedHighlightRect)}");
                        }
                    }
                }
            }

            foreach (object drawableObject in GetOrderedObjectsForCurrentPage())
            {
                if (drawableObject is RasterObject rasterObject)
                {
                    DrawRasterObjectOnPreview(e.Graphics, rasterObject, multiSelectionActive);
                }
                else if (drawableObject is ArrowObject arrowObject)
                {
                    DrawArrowObjectOnPreview(e.Graphics, arrowObject, multiSelectionActive);
                }
                else if (drawableObject is VectorShapeObject vectorShapeObject)
                {
                    DrawVectorShapeOnPreview(e.Graphics, vectorShapeObject);
                }
                else if (drawableObject is TextAnnotation annotation)
                {
                    DrawTextAnnotationOnPreview(e.Graphics, annotation, multiSelectionActive);
                }
            }
            DrawVectorShapeDraftOnPreview(e.Graphics);

            if (!multiSelectionActive)
            {
                DrawSelectedRasterOverlayOnTop(e.Graphics);
                DrawSelectedArrowOverlayOnTop(e.Graphics);
                DrawSelectedVectorOverlayOnTop(e.Graphics);
            }

            if (IsCurrentPageMarkedForDeletion())
            {
                using (var overlayBrush = new SolidBrush(System.Drawing.Color.FromArgb(120, 180, 180, 180)))
                {
                    e.Graphics.FillRectangle(overlayBrush, pdfViewer.ClientRectangle);
                }

                string lockMessage = LocalizedText("Msg_PageMarkedForDeletion_EditLocked");
                using (var messageFont = new Font("Segoe UI", 18f, FontStyle.Bold, GraphicsUnit.Point))
                using (var messagePath = new System.Drawing.Drawing2D.GraphicsPath())
                {
                    var sf = new StringFormat
                    {
                        Alignment = StringAlignment.Center,
                        LineAlignment = StringAlignment.Center
                    };
                    float emSize = e.Graphics.DpiY * messageFont.Size / 72f;
                    messagePath.AddString(
                        lockMessage,
                        messageFont.FontFamily,
                        (int)messageFont.Style,
                        emSize,
                        pdfViewer.ClientRectangle,
                        sf);

                    var state = e.Graphics.Save();
                    e.Graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
                    e.Graphics.TextRenderingHint = System.Drawing.Text.TextRenderingHint.AntiAliasGridFit;
                    using (var haloPen = new Pen(System.Drawing.Color.FromArgb(240, 255, 255, 255), 6f))
                    using (var textBrush = new SolidBrush(System.Drawing.Color.FromArgb(235, 40, 40, 40)))
                    {
                        haloPen.LineJoin = System.Drawing.Drawing2D.LineJoin.Round;
                        e.Graphics.DrawPath(haloPen, messagePath);
                        e.Graphics.FillPath(textBrush, messagePath);
                    }
                    e.Graphics.Restore(state);
                }
            }


        }

