        private bool TrySelectRasterImagePath(out string selectedPath)
        {
            selectedPath = string.Empty;
            using (var openFileDialog = new OpenFileDialog())
            {
                openFileDialog.Filter = LocalizedText("Dialog_Filter_RasterImages");
                openFileDialog.Title = string.Format(LocalizedText("Dialog_Title_AddRasterImage"), Branding.ProductName);
                openFileDialog.CheckFileExists = true;
                openFileDialog.Multiselect = false;

                if (openFileDialog.ShowDialog(this) != DialogResult.OK)
                {
                    return false;
                }

                selectedPath = openFileDialog.FileName;
                return true;
            }
        }

        private static bool TryGetRasterImageMetrics(RasterObject rasterObject, out int width, out int height, out decimal aspectRatio)
        {
            width = 0;
            height = 0;
            aspectRatio = 0m;
            if (!TryCreateRasterPreviewImage(rasterObject, out DrawingImage previewImage))
            {
                return false;
            }

            using (previewImage)
            {
                if (previewImage.Width <= 0 || previewImage.Height <= 0)
                {
                    return false;
                }

                width = previewImage.Width;
                height = previewImage.Height;
                aspectRatio = (decimal)width / height;
                return aspectRatio > 0m;
            }
        }

        private bool ApplyRasterObjectDialogChanges(RasterObject rasterObject, EditRasterDialog dlg)
        {
            if (rasterObject == null || dlg == null)
            {
                return false;
            }

            RectangleF updatedBounds = new RectangleF(
                dlg.PositionX,
                dlg.PositionY,
                dlg.WidthValue,
                dlg.HeightValue);
            int updatedRotation = NormalizeRotation(dlg.Rotation);
            float updatedOpacity = NormalizeOpacity(dlg.RasterOpacity);
            bool updatedTransparentBackground = dlg.TransparentBackground;
            bool updatedLockAspect = dlg.LockAspect;
            bool updatedLocked = dlg.IsLocked;
            string selectedPathToApply = dlg.ReplacementImagePath;

            try
            {
                if (!string.IsNullOrWhiteSpace(selectedPathToApply))
                {
                    using (var image = DrawingImage.FromFile(selectedPathToApply))
                    {
                        if (image.Width <= 0 || image.Height <= 0)
                        {
                            return false;
                        }
                    }
                }

                bool changed = RasterObjectChanged(
                    rasterObject,
                    updatedBounds,
                    updatedRotation,
                    updatedOpacity,
                    updatedTransparentBackground,
                    updatedLockAspect,
                    updatedLocked,
                    string.IsNullOrWhiteSpace(selectedPathToApply) ? rasterObject.FilePath : selectedPathToApply);
                if (!changed)
                {
                    return false;
                }

                rasterObject.Bounds = updatedBounds;
                rasterObject.Rotation = updatedRotation;
                rasterObject.Opacity = updatedOpacity;
                rasterObject.TransparentBackground = updatedTransparentBackground;
                rasterObject.LockAspect = updatedLockAspect;
                rasterObject.IsLocked = updatedLocked;

                if (!string.IsNullOrWhiteSpace(selectedPathToApply))
                {
                    rasterObject.SourceType = RasterSourceFile;
                    rasterObject.FilePath = selectedPathToApply;
                    rasterObject.EmbeddedBytes = null;
                    rasterObject.MimeType = GetRasterMimeTypeFromPath(selectedPathToApply);
                }

                ConstrainRasterObjectToPage(rasterObject);
                rasterObject.UpdatedAtUtc = DateTime.UtcNow;
                dlg.SyncControlsFromObject(rasterObject);

                projectWasChangedAfterLastSave = true;
                saveProjectButton.Enabled = true;
                saveProjectMenuItem.Enabled = true;
                pdfViewer.Invalidate();
                return true;
            }
            catch (Exception ex)
            {
                ShowInfoMessage(LocalizedFormat("Err_RasterImageLoad", ex.Message));
                LogDebug("Edit raster object failed: " + ex);
                return false;
            }
        }

        private void EditRasterObject(RasterObject rasterObject)
        {
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            using (var dlg = new EditRasterDialog())
            {
                dlg.PositionX = rasterObject.Bounds.X;
                dlg.PositionY = rasterObject.Bounds.Y;
                dlg.WidthValue = rasterObject.Bounds.Width;
                dlg.HeightValue = rasterObject.Bounds.Height;
                dlg.Rotation = NormalizeRotation(rasterObject.Rotation);
                dlg.RasterOpacity = NormalizeOpacity(rasterObject.Opacity);
                dlg.TransparentBackground = rasterObject.TransparentBackground;
                dlg.LockAspect = rasterObject.LockAspect;
                dlg.IsLocked = rasterObject.IsLocked;
                dlg.SourceType = rasterObject.SourceType;
                dlg.FilePath = rasterObject.FilePath;
                dlg.ViewScaleFactor = Math.Max(0.01f, scaleFactor);
                var pageSize = GetPageSizeWithOffset(currentPage);
                dlg.PageWidth = pageSize.Width;
                dlg.PageHeight = pageSize.Height;
                if (TryGetRasterImageMetrics(rasterObject, out int sourcePixelWidth, out int sourcePixelHeight, out decimal sourceAspectRatio))
                {
                    dlg.SourcePixelWidth = sourcePixelWidth;
                    dlg.SourcePixelHeight = sourcePixelHeight;
                    dlg.SourceAspectRatio = sourceAspectRatio;
                }
                dlg.SelectReplacementImage = () =>
                {
                    return TrySelectRasterImagePath(out string selectedPath) ? selectedPath : string.Empty;
                };
                dlg.ApplyChanges = () =>
                {
                    ApplyRasterObjectDialogChanges(rasterObject, dlg);
                };

                if (dlg.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                ApplyRasterObjectDialogChanges(rasterObject, dlg);
            }
        }

        private void ResetRasterObjectSize(RasterObject rasterObject)
        {
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return;
            }

            if (!EnsureCurrentPageEditable(true))
            {
                return;
            }

            RectangleF initialBounds = GetResolvedRasterInitialBounds(rasterObject);
            if (!HasPositiveSize(initialBounds))
            {
                return;
            }

            RectangleF currentBounds = rasterObject.Bounds;
            float centerX = currentBounds.X + (currentBounds.Width / 2f);
            float centerY = currentBounds.Y + (currentBounds.Height / 2f);
            var resizedBounds = new RectangleF(
                centerX - (initialBounds.Width / 2f),
                centerY - (initialBounds.Height / 2f),
                initialBounds.Width,
                initialBounds.Height);

            if (Math.Abs(currentBounds.Width - resizedBounds.Width) < 0.001f &&
                Math.Abs(currentBounds.Height - resizedBounds.Height) < 0.001f)
            {
                return;
            }

            rasterObject.Bounds = resizedBounds;
            ConstrainRasterObjectToPage(rasterObject);
            rasterObject.UpdatedAtUtc = DateTime.UtcNow;
            projectWasChangedAfterLastSave = true;
            saveProjectButton.Enabled = true;
            saveProjectMenuItem.Enabled = true;
            pdfViewer.Invalidate();
        }

        private bool TryGetRasterResizeHandleRects(RasterObject rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> handles)
        {
            handles = null;
            if (rasterObject == null || rasterObject.PageNumber != currentPage)
            {
                return false;
            }

            RectangleF bounds = GetRasterObjectScreenBounds(rasterObject);
            if (bounds.Width <= 0f || bounds.Height <= 0f)
            {
                return false;
            }

            PointF center = GetRasterObjectScreenCenter(rasterObject);
            int rotation = NormalizeRotation(rasterObject.Rotation);
            PointF vx = RotateVector(new PointF(bounds.Width / 2f, 0f), rotation);
            PointF vy = RotateVector(new PointF(0f, bounds.Height / 2f), rotation);

            PointF topLeft = new PointF(center.X - vx.X - vy.X, center.Y - vx.Y - vy.Y);
            PointF top = new PointF(center.X - vy.X, center.Y - vy.Y);
            PointF topRight = new PointF(center.X + vx.X - vy.X, center.Y + vx.Y - vy.Y);
            PointF right = new PointF(center.X + vx.X, center.Y + vx.Y);
            PointF bottomRight = new PointF(center.X + vx.X + vy.X, center.Y + vx.Y + vy.Y);
            PointF bottom = new PointF(center.X + vy.X, center.Y + vy.Y);
            PointF bottomLeft = new PointF(center.X - vx.X + vy.X, center.Y - vx.Y + vy.Y);
            PointF left = new PointF(center.X - vx.X, center.Y - vx.Y);

            handles = new Dictionary<RasterResizeHandleType, RectangleF>
            {
                [RasterResizeHandleType.TopLeft] = BuildHandleRect(topLeft, RasterResizeHandleSize),
                [RasterResizeHandleType.Top] = BuildHandleRect(top, RasterResizeHandleSize),
                [RasterResizeHandleType.TopRight] = BuildHandleRect(topRight, RasterResizeHandleSize),
                [RasterResizeHandleType.Right] = BuildHandleRect(right, RasterResizeHandleSize),
                [RasterResizeHandleType.BottomRight] = BuildHandleRect(bottomRight, RasterResizeHandleSize),
                [RasterResizeHandleType.Bottom] = BuildHandleRect(bottom, RasterResizeHandleSize),
                [RasterResizeHandleType.BottomLeft] = BuildHandleRect(bottomLeft, RasterResizeHandleSize),
                [RasterResizeHandleType.Left] = BuildHandleRect(left, RasterResizeHandleSize)
            };
            return true;
        }

        private bool TryGetRasterResizeHandleAtPoint(RasterObject rasterObject, Point location, out RasterResizeHandleType handle)
        {
            handle = RasterResizeHandleType.None;
            if (!TryGetRasterResizeHandleRects(rasterObject, out Dictionary<RasterResizeHandleType, RectangleF> handles))
            {
                return false;
            }

            foreach (var kvp in handles)
            {
                if (kvp.Value.Contains(location))
                {
                    handle = kvp.Key;
                    return true;
                }
            }

            return false;
        }

        private static RasterResizeHandleType GetOppositeRasterResizeHandle(RasterResizeHandleType handle)
        {
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                    return RasterResizeHandleType.BottomRight;
                case RasterResizeHandleType.Top:
                    return RasterResizeHandleType.Bottom;
                case RasterResizeHandleType.TopRight:
                    return RasterResizeHandleType.BottomLeft;
                case RasterResizeHandleType.Right:
                    return RasterResizeHandleType.Left;
                case RasterResizeHandleType.BottomRight:
                    return RasterResizeHandleType.TopLeft;
                case RasterResizeHandleType.Bottom:
                    return RasterResizeHandleType.Top;
                case RasterResizeHandleType.BottomLeft:
                    return RasterResizeHandleType.TopRight;
                case RasterResizeHandleType.Left:
                    return RasterResizeHandleType.Right;
                default:
                    return RasterResizeHandleType.None;
            }
        }

        private static PointF GetRasterResizeHandleLocalPoint(RasterResizeHandleType handle, float halfWidth, float halfHeight)
        {
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                    return new PointF(-halfWidth, -halfHeight);
                case RasterResizeHandleType.Top:
                    return new PointF(0f, -halfHeight);
                case RasterResizeHandleType.TopRight:
                    return new PointF(halfWidth, -halfHeight);
                case RasterResizeHandleType.Right:
                    return new PointF(halfWidth, 0f);
                case RasterResizeHandleType.BottomRight:
                    return new PointF(halfWidth, halfHeight);
                case RasterResizeHandleType.Bottom:
                    return new PointF(0f, halfHeight);
                case RasterResizeHandleType.BottomLeft:
                    return new PointF(-halfWidth, halfHeight);
                case RasterResizeHandleType.Left:
                    return new PointF(-halfWidth, 0f);
                default:
                    return PointF.Empty;
            }
        }

        private static PointF GetRasterResizeSign(RasterResizeHandleType handle)
        {
            float sx = 0f;
            float sy = 0f;
            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                case RasterResizeHandleType.Left:
                case RasterResizeHandleType.BottomLeft:
                    sx = -1f;
                    break;
                case RasterResizeHandleType.TopRight:
                case RasterResizeHandleType.Right:
                case RasterResizeHandleType.BottomRight:
                    sx = 1f;
                    break;
            }

            switch (handle)
            {
                case RasterResizeHandleType.TopLeft:
                case RasterResizeHandleType.Top:
                case RasterResizeHandleType.TopRight:
                    sy = -1f;
                    break;
                case RasterResizeHandleType.BottomLeft:
                case RasterResizeHandleType.Bottom:
                case RasterResizeHandleType.BottomRight:
                    sy = 1f;
                    break;
            }

            return new PointF(sx, sy);
        }

        private static PointF GetRasterResizeHandleWorldPoint(RectangleF bounds, int rotation, RasterResizeHandleType handle)
        {
            PointF center = new PointF(bounds.X + (bounds.Width / 2f), bounds.Y + (bounds.Height / 2f));
            PointF localHandle = GetRasterResizeHandleLocalPoint(handle, bounds.Width / 2f, bounds.Height / 2f);
            PointF rotatedHandle = RotateVector(localHandle, NormalizeRotation(rotation));
            return new PointF(center.X + rotatedHandle.X, center.Y + rotatedHandle.Y);
        }

        private static float NormalizeDegrees(float angle)
        {
            float normalized = angle % 360f;
            if (normalized < 0f)
            {
                normalized += 360f;
            }
            return normalized;
        }

        private static Cursor GetDirectionalResizeCursor(float absoluteAngle)
        {
            // Cursor orientation is symmetric every 180 degrees.
            float angle = NormalizeDegrees(absoluteAngle) % 180f;
            if (angle >= 22.5f && angle < 67.5f)
            {
                return Cursors.SizeNWSE;
            }
            if (angle >= 67.5f && angle < 112.5f)
            {
                return Cursors.SizeNS;
            }
            if (angle >= 112.5f && angle < 157.5f)
            {
                return Cursors.SizeNESW;
            }
            return Cursors.SizeWE;
        }

        private static float GetHandleBaseAngle(RasterResizeHandleType handle)
        {
            switch (handle)
            {
                case RasterResizeHandleType.Right:
                    return 0f;
                case RasterResizeHandleType.TopRight:
                    return 315f;
                case RasterResizeHandleType.Top:
                    return 270f;
                case RasterResizeHandleType.TopLeft:
                    return 225f;
                case RasterResizeHandleType.Left:
                    return 180f;
                case RasterResizeHandleType.BottomLeft:
                    return 135f;
                case RasterResizeHandleType.Bottom:
                    return 90f;
                case RasterResizeHandleType.BottomRight:
                    return 45f;
                default:
                    return 0f;
            }
        }

        private static Cursor GetCursorForRasterResizeHandle(RasterResizeHandleType handle, int rotation)
        {
            if (handle == RasterResizeHandleType.None)
            {
                return Cursors.Default;
            }

            float angle = GetHandleBaseAngle(handle) + NormalizeRotation(rotation);
            return GetDirectionalResizeCursor(angle);
        }

        private bool TryUpdateRasterHoverCursor(Point location)
        {
            if (selectedRasterObject == null || selectedRasterObject.PageNumber != currentPage)
            {
                return false;
            }

            if (selectedRasterObject.IsLocked)
            {
                if (IsPointInsideRasterObject(selectedRasterObject, location))
                {
                    this.Cursor = Cursors.Default;
                    return true;
                }

                return false;
            }

            if (TryGetRasterResizeHandleAtPoint(selectedRasterObject, location, out RasterResizeHandleType handle))
            {
                this.Cursor = GetCursorForRasterResizeHandle(handle, selectedRasterObject.Rotation);
                return true;
            }

            if (TryGetRasterRotationHandleRect(selectedRasterObject, out RectangleF rotationHandleRect, out _) && rotationHandleRect.Contains(location))
            {
                this.Cursor = Cursors.Hand;
                return true;
            }

            if (IsPointInsideRasterObject(selectedRasterObject, location))
            {
                this.Cursor = Cursors.SizeAll;
                return true;
            }

            return false;
        }

        private float GetAngleDegrees(PointF center, Point point)
        {
            return (float)(Math.Atan2(point.Y - center.Y, point.X - center.X) * (180d / Math.PI));
        }

        private bool TryHandleRasterMouseDown(Point location)
        {
            if (selectedRasterObject != null && selectedRasterObject.PageNumber == currentPage && !selectedRasterObject.IsLocked)
            {
                if (TryGetRasterResizeHandleAtPoint(selectedRasterObject, location, out RasterResizeHandleType handle))
                {
                    rasterObjectToResize = selectedRasterObject;
                    isResizingRasterObject = true;
                    rasterResizeHandle = handle;
                    rasterResizeStartBounds = selectedRasterObject.Bounds;
                    rasterResizeStartRotation = NormalizeRotation(selectedRasterObject.Rotation);
                    RasterResizeHandleType oppositeHandle = GetOppositeRasterResizeHandle(handle);
                    rasterResizeAnchorWorld = GetRasterResizeHandleWorldPoint(
                        rasterResizeStartBounds,
                        rasterResizeStartRotation,
                        oppositeHandle);
                    this.Cursor = GetCursorForRasterResizeHandle(handle, selectedRasterObject.Rotation);
                    return true;
                }

                if (TryGetRasterRotationHandleRect(selectedRasterObject, out RectangleF handleRect, out _) && handleRect.Contains(location))
                {
                    rasterObjectToRotate = selectedRasterObject;
                    isRotatingRasterObject = true;
                    rasterRotationStartValue = NormalizeRotation(selectedRasterObject.Rotation);
                    rasterRotationStartAngle = GetAngleDegrees(GetRasterObjectScreenCenter(selectedRasterObject), location);
                    this.Cursor = Cursors.Hand;
                    return true;
                }
            }

            RasterObject hitObject = rasterObjects
                .Where(obj => obj != null && obj.PageNumber == currentPage)
                .Reverse()
                .FirstOrDefault(obj => IsPointInsideRasterObject(obj, location));

            if (hitObject == null)
            {
                selectedRasterObject = null;
                ClearRasterIconClickState();
                return false;
            }

            EnsureRasterObjectId(hitObject);
            selectedRasterObject = hitObject;
            selectedVectorShape = null;
            ClearGroupSelection();
            ClearRasterIconClickState();
            if (hitObject.IsLocked)
            {
                return true;
            }

            rasterObjectToMove = hitObject;
            isMovingRasterObject = true;
            startPoint = location;
            PointF mouseDoc = new PointF(location.X / scaleFactor, location.Y / scaleFactor);
            rasterMoveMouseOffset = new PointF(mouseDoc.X - hitObject.Bounds.X, mouseDoc.Y - hitObject.Bounds.Y);
            this.Cursor = Cursors.SizeAll;
            return true;
        }

        private static Bitmap ApplyTransparentBackgroundFromTopLeft(Bitmap source)
        {
            if (source == null)
            {
                return null;
            }

            Bitmap working = new Bitmap(source.Width, source.Height, PixelFormat.Format32bppArgb);
            using (Graphics g = Graphics.FromImage(working))
            {
                g.DrawImage(source, 0, 0, source.Width, source.Height);
            }

            if (working.Width <= 0 || working.Height <= 0)
            {
                return working;
            }

            Rectangle rect = new Rectangle(0, 0, working.Width, working.Height);
            BitmapData data = null;
            try
            {
                data = working.LockBits(rect, ImageLockMode.ReadWrite, PixelFormat.Format32bppArgb);
                int stride = data.Stride;
                int rowBytes = Math.Abs(stride);
                int totalBytes = rowBytes * working.Height;
                byte[] buffer = new byte[totalBytes];
                Marshal.Copy(data.Scan0, buffer, 0, totalBytes);

                int firstRowStart = stride >= 0 ? 0 : (working.Height - 1) * rowBytes;
                byte keyB = buffer[firstRowStart];
                byte keyG = buffer[firstRowStart + 1];
                byte keyR = buffer[firstRowStart + 2];

                for (int y = 0; y < working.Height; y++)
                {
                    int rowStart = stride >= 0 ? y * rowBytes : (working.Height - 1 - y) * rowBytes;
                    for (int x = 0; x < working.Width; x++)
                    {
                        int idx = rowStart + (x * 4);
                        if (buffer[idx] == keyB && buffer[idx + 1] == keyG && buffer[idx + 2] == keyR)
                        {
                            buffer[idx + 3] = 0;
                        }
                    }
                }

                Marshal.Copy(buffer, 0, data.Scan0, totalBytes);
            }
            finally
            {
                if (data != null)
                {
                    working.UnlockBits(data);
                }
            }

            return working;
        }

        private static bool TryCreateRasterPreviewImage(RasterObject rasterObject, out DrawingImage image)
        {
            image = null;
            if (rasterObject == null)
            {
                return false;
            }

            try
            {
                if (rasterObject.EmbeddedBytes != null && rasterObject.EmbeddedBytes.Length > 0)
                {
                    using (var ms = new MemoryStream(rasterObject.EmbeddedBytes))
                    using (var src = DrawingImage.FromStream(ms))
                    {
                        using (var baseBitmap = new Bitmap(src))
                        {
                            image = rasterObject.TransparentBackground
                                ? ApplyTransparentBackgroundFromTopLeft(baseBitmap)
                                : new Bitmap(baseBitmap);
                        }
                        return true;
                    }
                }

                if (!string.IsNullOrWhiteSpace(rasterObject.FilePath) && File.Exists(rasterObject.FilePath))
                {
                    using (var src = DrawingImage.FromFile(rasterObject.FilePath))
                    {
                        using (var baseBitmap = new Bitmap(src))
                        {
                            image = rasterObject.TransparentBackground
                                ? ApplyTransparentBackgroundFromTopLeft(baseBitmap)
                                : new Bitmap(baseBitmap);
                        }
                        return true;
                    }
                }
            }
            catch
            {
                return false;
            }

            return false;
        }

        private static bool TryCreateRasterImageData(RasterObject rasterObject, out iText.IO.Image.ImageData imageData)
        {
            imageData = null;
            if (rasterObject == null)
            {
                return false;
            }

            try
            {
                if (rasterObject.EmbeddedBytes != null && rasterObject.EmbeddedBytes.Length > 0)
                {
                    if (!rasterObject.TransparentBackground)
                    {
                        imageData = iText.IO.Image.ImageDataFactory.Create(rasterObject.EmbeddedBytes);
                        return true;
                    }

                    using (var ms = new MemoryStream(rasterObject.EmbeddedBytes))
                    using (var src = DrawingImage.FromStream(ms))
                    using (var baseBitmap = new Bitmap(src))
                    using (var transformed = ApplyTransparentBackgroundFromTopLeft(baseBitmap))
                    using (var pngStream = new MemoryStream())
                    {
                        transformed.Save(pngStream, ImageFormat.Png);
                        imageData = iText.IO.Image.ImageDataFactory.Create(pngStream.ToArray());
                    }
                    return true;
                }

                if (!string.IsNullOrWhiteSpace(rasterObject.FilePath) && File.Exists(rasterObject.FilePath))
                {
                    if (!rasterObject.TransparentBackground)
                    {
                        byte[] fileBytes = File.ReadAllBytes(rasterObject.FilePath);
                        imageData = iText.IO.Image.ImageDataFactory.Create(fileBytes);
                        return true;
                    }

                    using (var src = DrawingImage.FromFile(rasterObject.FilePath))
                    using (var baseBitmap = new Bitmap(src))
                    using (var transformed = ApplyTransparentBackgroundFromTopLeft(baseBitmap))
                    using (var pngStream = new MemoryStream())
                    {
                        transformed.Save(pngStream, ImageFormat.Png);
                        imageData = iText.IO.Image.ImageDataFactory.Create(pngStream.ToArray());
                    }
                    return true;
                }
            }
            catch
            {
                return false;
            }

            return false;
        }

        private bool IsTextInputFocused()
        {
            Control focusedControl = GetFocusedControl(this);
            if (focusedControl == null)
            {
                return false;
            }

            if (focusedControl is TextBoxBase || focusedControl is NumericUpDown)
            {
                return true;
            }

            if (focusedControl is ComboBox comboBox && comboBox.DropDownStyle != ComboBoxStyle.DropDownList)
            {
                return true;
            }

            return false;
        }

        private static Control GetFocusedControl(Control root)
        {
            Control current = root;

            while (current is ContainerControl container && container.ActiveControl != null)
            {
                current = container.ActiveControl;
            }

            return current;
        }


        private void PDFForm_KeyDown(object sender, KeyEventArgs e)
        {
            if (pdf == null)
            {
                return;
            }

            switch (e.KeyCode)
            {

                case Keys.PageUp:
                    // Handle PageUp key:
                    PreviousPage(); // Method that goes to previous page
                    e.Handled = true;  // Indicates that event was handled
                    break;

                case Keys.PageDown:
                    // Handle PageDown key:
                    NextPage(); // Method that goes to next page
                    e.Handled = true;
                    break;

                case Keys.Home:
                    if (searchTextBox.Focused)
                    {
                        break;
                    }
                    FirstPage();
                    e.Handled = true;
                    break;

                case Keys.End:
                    if (searchTextBox.Focused)
                    {
                        break;
                    }
                    LastPage();
                    e.Handled = true;
                    break;
            }
        }

        private void OpenLastPdfProjectToolStripMenuItem_Click(object sender, EventArgs e)
        {
            // Get saved paths from Properties.Settings
            string lastPdf = Properties.Settings.Default.LastPdfPath;
            string lastPap = Properties.Settings.Default.LastPapPath;
            bool hasPdf = !string.IsNullOrWhiteSpace(lastPdf) && File.Exists(lastPdf);
            bool hasProject = !string.IsNullOrWhiteSpace(lastPap) && File.Exists(lastPap);
            ResumeState resumeState = LoadResumeState();

            try
            {
                if (hasPdf)
                {
                    // Load PDF
                    inputPdfPath = lastPdf;
                    inputProjectPath = "";
                    lastSavedProjectName = "";
                    LoadPdf();
                    if (hasProject)
                    {
                        bool registerAsProject = !IsAutoResumeProjectPath(lastPap);
                        LoadRedactionBlocks(lastPap, registerAsProject: registerAsProject);
                    }
                    RestoreViewFromResumeStateIfMatches(resumeState);
                }
                else if (hasProject)
                {
                    bool registerAsProject = !IsAutoResumeProjectPath(lastPap);
                    LoadRedactionBlocks(lastPap, registerAsProject: registerAsProject);
                    RestoreViewFromResumeStateIfMatches(resumeState);
                }
                else
                {
                    MessageBox.Show(this, Resources.Msg_CannotLoadRecentFiles, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                }
            }
            catch (Exception ex)
            {
                    MessageBox.Show(this, string.Format(Resources.Err_LoadRecentFiles, ex.Message),
                        Resources.Title_Error, MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
        }

        private List<string> LoadRecentFiles()
        {
            string raw = Properties.Settings.Default.RecentFiles;
            if (string.IsNullOrWhiteSpace(raw))
            {
                return new List<string>();
            }

            try
            {
                var files = JsonConvert.DeserializeObject<List<string>>(raw);
                return files ?? new List<string>();
            }
            catch
            {
                return new List<string>();
            }
        }

        private void SaveRecentFiles(List<string> files)
        {
            Properties.Settings.Default.RecentFiles = JsonConvert.SerializeObject(files);
            Properties.Settings.Default.Save();
        }

        private void AddRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            string ext = Path.GetExtension(filePath);
            if (!string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
            {
                return;
            }

            string fullPath = Path.GetFullPath(filePath);
            var files = LoadRecentFiles();
            files.RemoveAll(path => string.Equals(path, fullPath, StringComparison.OrdinalIgnoreCase));
            files.Insert(0, fullPath);

            while (files.Count > RecentFilesLimit)
            {
                files.RemoveAt(files.Count - 1);
            }

            SaveRecentFiles(files);
            UpdateRecentFilesMenu();
        }

        private void RemoveRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            var files = LoadRecentFiles();
            int removedCount = files.RemoveAll(path => string.Equals(path, filePath, StringComparison.OrdinalIgnoreCase));
            if (removedCount > 0)
            {
                SaveRecentFiles(files);
            }
        }

        private void UpdateRecentFilesMenu()
        {
            if (recentFilesMenuItem == null)
            {
                return;
            }

            var theme = CurrentTheme;
            recentFilesMenuItem.DropDownItems.Clear();

            var files = LoadRecentFiles();
            var uniqueFiles = new List<string>();
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (var path in files)
            {
                if (string.IsNullOrWhiteSpace(path))
                {
                    continue;
                }

                string ext = Path.GetExtension(path);
                if (!string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                if (seen.Add(path))
                {
                    uniqueFiles.Add(path);
                }
            }

            if (uniqueFiles.Count == 0)
            {
                var emptyItem = new ToolStripMenuItem(Resources.Menu_RecentFiles_Empty);
                emptyItem.Enabled = false;
                emptyItem.ForeColor = theme.TextSecondaryColor;
                recentFilesMenuItem.DropDownItems.Add(emptyItem);
                recentFilesMenuItem.Enabled = false;
                return;
            }

            recentFilesMenuItem.Enabled = true;

            int count = Math.Min(uniqueFiles.Count, RecentFilesLimit);
            for (int i = 0; i < count; i++)
            {
                string path = uniqueFiles[i];
                string fileName = Path.GetFileName(path);
                var item = new ToolStripMenuItem($"{i + 1}. {fileName}");
                item.Tag = path;
                item.ToolTipText = path;
                item.AutoToolTip = true;
                if (!File.Exists(path))
                {
                    item.ForeColor = theme.TextSecondaryColor;
                }
                else
                {
                    item.ForeColor = theme.TextPrimaryColor;
                }
                item.Click += RecentFileMenuItem_Click;
                recentFilesMenuItem.DropDownItems.Add(item);
            }
        }

        private void RecentFilesMenuItem_DropDownOpening(object sender, EventArgs e)
        {
            UpdateRecentFilesMenu();
        }

        private void RecentFileMenuItem_Click(object sender, EventArgs e)
        {
            if (sender is ToolStripMenuItem menuItem && menuItem.Tag is string filePath)
            {
                OpenRecentFile(filePath);
            }
        }

        private void OpenRecentFile(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return;
            }

            if (!File.Exists(filePath))
            {
                MessageBox.Show(this, Resources.Msg_CannotLoadRecentFiles, Resources.Title_Warning, MessageBoxButtons.OK, MessageBoxIcon.Warning);
                RemoveRecentFile(filePath);
                UpdateRecentFilesMenu();
                return;
            }

            string ext = Path.GetExtension(filePath);
            if (string.Equals(ext, ".pdf", StringComparison.OrdinalIgnoreCase))
            {
                OpenPdfFromPath(filePath);
                return;
            }

            if (string.Equals(ext, ProjectFileExtension, StringComparison.OrdinalIgnoreCase) ||
                string.Equals(ext, LegacyProjectFileExtension, StringComparison.OrdinalIgnoreCase))
            {
                LoadRedactionBlocks(filePath);
            }
        }

