        private void ButtonAddDirectory_Click(object sender, EventArgs e)
        {
            using (var dlg = new FolderBrowserDialog())
            {
                if (dlg.ShowDialog(this) == DialogResult.OK)
                {
                    var files = Directory.GetFiles(dlg.SelectedPath, "*.pdf");
